    const label = status === "ready_to_operate"
      ? "Ready to Operate"
      : status === "needs_watch_check_in"
        ? "Needs Watch Check-In"
        : status === "needs_stabilization_handoff"
          ? "Needs Stabilization Handoff"
          : status === "needs_operational_review"
