function normalizeSnapshotStatus(value) {
  return String(value ?? "").trim().toLowerCase();
}

function snapshotDateMs(value) {
  const ms = new Date(value || "").getTime();
  return Number.isNaN(ms) ? -1 : ms;
}

function countSnapshotItems(items = [], statuses = []) {
  const normalizedStatuses = new Set(statuses.map((value) => normalizeSnapshotStatus(value)));
  return items.reduce((count, item) => {
    return normalizedStatuses.has(normalizeSnapshotStatus(item?.status)) ? count + 1 : count;
  }, 0);
}

function latestSnapshotTimestamp(values = []) {
  let latest = null;
  let latestMs = -1;
  for (const value of values) {
    const ms = snapshotDateMs(value);
    if (ms <= latestMs) {
      continue;
    }
    latest = value;
    latestMs = ms;
  }
  return latest;
}

function buildSnapshotLatestLaunchReceipts(auditLogs = [], limit = 5, channel = null) {
  const normalizedChannel = channel ? normalizeChannel(channel, "stable") : null;
  return auditLogs
    .map((item) => {
      const metadata = item?.metadata && typeof item.metadata === "object" ? item.metadata : {};
      const receipt = metadata.launchReceipt && typeof metadata.launchReceipt === "object"
        ? metadata.launchReceipt
        : null;
      if (!receipt) {
        return null;
      }
      return {
        auditLogId: item.id || null,
        eventType: item.eventType || null,
        actorType: item.actorType || null,
        actorId: item.actorId || null,
        entityType: item.entityType || null,
        entityId: item.entityId || null,
        productCode: metadata.productCode || metadata.code || metadata.projectCode || metadata.softwareCode || null,
        channel: metadata.channel || "stable",
        operation: receipt.operation || null,
        operationLabel: receipt.operationLabel || null,
        summary: receipt.summary || "",
        handoffFileName: receipt.handoffFileName || null,
        handoffGeneratedAt: receipt.handoffGeneratedAt || null,
        hasHandoffText: Boolean(receipt.hasHandoffText),
        mainlineGateStatus: receipt.mainlineGate?.status || null,
        mainlineGateHeadline: receipt.mainlineGate?.headline || null,
        productionEvidenceRemainingCount: receipt.productionEvidence?.remainingCount ?? null,
        productionEvidenceCompletedCount: receipt.productionEvidence?.completedCount ?? null,
        productionEvidenceNextActionKey: receipt.productionEvidence?.nextActionKey || null,
        productionEvidenceNextActionTitle: receipt.productionEvidence?.nextActionTitle || null,
        productionEvidenceNextOperation: receipt.productionEvidence?.nextOperation || null,
        firstLaunchInventoryCreatedBatchCount: receipt.firstLaunchInventory?.createdBatchCount ?? null,
        firstLaunchInventoryCreatedCardCount: receipt.firstLaunchInventory?.createdCardCount ?? null,
        firstLaunchDutyHandoffDownloadKey: receipt.firstLaunchDuty?.handoffDownloadKey || null,
        firstLaunchDutyPrimaryWorkspaceKey: receipt.firstLaunchDuty?.primaryWorkspaceKey || null,
        firstLaunchDutyPrimaryDownloadKey: receipt.firstLaunchDuty?.primaryDownloadKey || null,
        firstLaunchDutyActionCount: receipt.firstLaunchDuty?.actionCount ?? null,
        firstLaunchDutyDeliveryExportStatus: receipt.firstLaunchDuty?.deliveryExportStatus || null,
        firstLaunchDutyDeliveryExportCardCount: receipt.firstLaunchDuty?.deliveryExportCardCount ?? null,
        firstLaunchDutyDeliveryExportUsageStatus: receipt.firstLaunchDuty?.deliveryExportUsageStatus || null,
        firstLaunchDutyDeliveryExportCsvDownloadKey: receipt.firstLaunchDuty?.deliveryExportCsvDownloadKey || null,
        firstLaunchDutyDeliveryExportCsvHref: receipt.firstLaunchDuty?.deliveryExportCsvHref || null,
        firstLaunchDutyDeliveryExportZipDownloadKey: receipt.firstLaunchDuty?.deliveryExportZipDownloadKey || null,
        firstLaunchDutyDeliveryExportChecksumDownloadKey: receipt.firstLaunchDuty?.deliveryExportChecksumDownloadKey || null,
        firstLaunchDutyFirstUserValidationStatus: receipt.firstLaunchDuty?.firstUserValidationStatus || null,
        firstLaunchDutyFirstUserValidationActionCount: receipt.firstLaunchDuty?.firstUserValidationActionCount ?? null,
        firstLaunchDutyFirstUserValidationRemainingCount: receipt.firstLaunchDuty?.firstUserValidationRemainingCount ?? null,
        firstLaunchDutyFirstUserValidationNextActionKey: receipt.firstLaunchDuty?.firstUserValidationNextActionKey || null,
        firstLaunchDutyFirstUserValidationNextStage: receipt.firstLaunchDuty?.firstUserValidationNextStage || null,
        firstLaunchDutyFirstUserValidationNextOwnerRole: receipt.firstLaunchDuty?.firstUserValidationNextOwnerRole || null,
        firstLaunchDutyFirstUserValidationProductionNextOperation: receipt.firstLaunchDuty?.firstUserValidationProductionNextOperation || null,
        postLaunchLifecycleStatus: receipt.postLaunchLifecycle?.status || null,
        postLaunchLifecyclePhaseCount: receipt.postLaunchLifecycle?.phaseCount ?? null,
        postLaunchLifecycleReadyCount: receipt.postLaunchLifecycle?.readyCount ?? null,
        postLaunchLifecycleHoldCount: receipt.postLaunchLifecycle?.holdCount ?? null,
        postLaunchLifecycleReviewCount: receipt.postLaunchLifecycle?.reviewCount ?? null,
        postLaunchLifecycleNextActionKey: receipt.postLaunchLifecycle?.nextActionKey || null,
        postLaunchLifecycleNextActionTitle: receipt.postLaunchLifecycle?.nextActionTitle || null,
        postLaunchLifecycleNextOperation: receipt.postLaunchLifecycle?.nextOperation || null,
        postLaunchLifecyclePrimaryWorkspaceKey: receipt.postLaunchLifecycle?.primaryWorkspaceKey || null,
        postLaunchLifecyclePrimaryWorkspaceAutofocus: receipt.postLaunchLifecycle?.primaryWorkspaceAutofocus || null,
        postLaunchLifecyclePrimaryDownloadKey: receipt.postLaunchLifecycle?.primaryDownloadKey || null,
        postLaunchLifecyclePrimaryDownloadFormat: receipt.postLaunchLifecycle?.primaryDownloadFormat || null,
        postLaunchLifecyclePrimaryDownloadFileName: receipt.postLaunchLifecycle?.primaryDownloadFileName || null,
        postLaunchLifecyclePrimaryDownloadHref: receipt.postLaunchLifecycle?.primaryDownloadHref || null,
        operationalReadinessStatus: receipt.operationalReadiness?.status || null,
        operationalReadinessLabel: receipt.operationalReadiness?.label || null,
        operationalReadinessReady: receipt.operationalReadiness?.readyToOperate === true,
        operationalReadinessBlockingCount: receipt.operationalReadiness?.blockingCount ?? null,
        operationalReadinessBlockingOperationCount: receipt.operationalReadiness?.blockingOperationCount ?? null,
        operationalReadinessWatchReady: receipt.operationalReadiness?.watchReady === true,
        operationalReadinessWatchCheckInStatus: receipt.operationalReadiness?.watchCheckInStatus || null,
        operationalReadinessWatchRecordDraftStatus: receipt.operationalReadiness?.watchRecordDraftStatus || null,
        operationalReadinessWatchRecordDraftRecordCount: receipt.operationalReadiness?.watchRecordDraftRecordCount ?? null,
        operationalReadinessStabilizationStatus: receipt.operationalReadiness?.stabilizationStatus || null,
        operationalReadinessSteadyStateStatus: receipt.operationalReadiness?.steadyStateStatus || null,
        operationalReadinessNextActionKey: receipt.operationalReadiness?.nextActionKey || null,
        operationalReadinessNextOperation: receipt.operationalReadiness?.nextOperation || null,
        operationalReadinessPrimaryWorkspaceKey: receipt.operationalReadiness?.primaryWorkspaceKey || null,
        operationalReadinessPrimaryWorkspaceAutofocus: receipt.operationalReadiness?.primaryWorkspaceAutofocus || null,
        operationalReadinessPrimaryDownloadKey: receipt.operationalReadiness?.primaryDownloadKey || null,
        operationalReadinessPrimaryDownloadFormat: receipt.operationalReadiness?.primaryDownloadFormat || null,
        operationalReadinessPrimaryDownloadFileName: receipt.operationalReadiness?.primaryDownloadFileName || null,
        operationalReadinessPrimaryDownloadHref: receipt.operationalReadiness?.primaryDownloadHref || null,
        launchOpsOverviewContext: normalizeLaunchOpsOverviewContext(receipt.launchOpsOverviewContext),
        initialLaunchOperatorDecision: receipt.initialLaunchOperator?.decision || null,
        initialLaunchOperatorStatus: receipt.initialLaunchOperator?.status || null,
        initialLaunchOperatorPrimaryActionKey: receipt.initialLaunchOperator?.primaryActionKey || null,
        initialLaunchOperatorActionCount: receipt.initialLaunchOperator?.actionCount ?? null,
        initialLaunchOperatorNextStage: receipt.initialLaunchOperator?.nextStage || null,
        initialLaunchOperatorNextActionKey: receipt.initialLaunchOperator?.nextActionKey || null,
        initialLaunchOperatorNextOperation: receipt.initialLaunchOperator?.nextOperation || null,
        initialLaunchOperatorNextDownloadKey: receipt.initialLaunchOperator?.nextDownloadKey || null,
        initialLaunchOperatorNextDownloadFileName: receipt.initialLaunchOperator?.nextDownloadFileName || null,
        initialLaunchOperatorNextDownloadHref: receipt.initialLaunchOperator?.nextDownloadHref || null,
        initialLaunchOperatorWorkspaceKey: receipt.initialLaunchOperator?.workspaceKey || null,
        initialLaunchOperatorWorkspaceAutofocus: receipt.initialLaunchOperator?.workspaceAutofocus || null,
        receiptVisibility: receipt.visibility || null,
        createdAt: item.createdAt || null
      };
    })
    .filter((item) => {
      if (!item) {
        return false;
      }
      if (!normalizedChannel) {
        return true;
      }
      return normalizeChannel(item.channel, "stable") === normalizedChannel;
    })
    .sort((left, right) => snapshotDateMs(right.createdAt || right.handoffGeneratedAt) - snapshotDateMs(left.createdAt || left.handoffGeneratedAt))
    .slice(0, Math.max(1, Number(limit || 5)));
}

function buildStabilizationHandoffConfirmationPayload(item = null) {
  if (!item || typeof item !== "object") {
    return null;
  }
  const metadata = item.metadata && typeof item.metadata === "object" ? item.metadata : {};
  const confirmedBy = item.confirmedBy && typeof item.confirmedBy === "object"
    ? item.confirmedBy
    : {
        actorType: item.actorType || null,
        actorScope: metadata.actorType || null,
        actorId: item.actorId || null,
        username: metadata.actorUsername || null,
        role: metadata.actorRole || null
      };
  const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(
    item.launchOpsOverviewContext
    || metadata.launchOpsOverviewContext
  );
  return {
    auditLogId: item.auditLogId || item.id || null,
    eventType: item.eventType || "developer.ops.stabilization-handoff.confirm",
    entityType: item.entityType || "developer_ops_stabilization_handoff",
    entityId: item.entityId || null,
    productCode: item.productCode || metadata.productCode || null,
    channel: item.channel || metadata.channel || "stable",
    status: item.status || metadata.status || "confirmed",
    decision: item.decision || metadata.decision || "confirmed",
    handoffFileName: item.handoffFileName || metadata.handoffFileName || "developer-ops-stabilization-handoff.txt",
    confirmedAt: item.confirmedAt || metadata.confirmedAt || item.createdAt || null,
    confirmedBy,
    note: item.note || metadata.note || "",
    opsFiles: item.opsFiles || metadata.opsFiles || null,
    launchMainlineFiles: item.launchMainlineFiles || metadata.launchMainlineFiles || null,
    opsDownloads: item.opsDownloads || metadata.opsDownloads || null,
    launchMainlineDownloads: item.launchMainlineDownloads || metadata.launchMainlineDownloads || null,
    launchOpsOverviewContext,
    launchOpsOverviewDownload: buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext),
    createdAt: item.createdAt || null
  };
}

function buildSnapshotLatestStabilizationHandoffConfirmations(auditLogs = [], limit = 5) {
  return auditLogs
    .map((item) => {
      const metadata = item?.metadata && typeof item.metadata === "object" ? item.metadata : {};
      const eventType = item?.eventType || item?.event_type || "";
      const entityType = item?.entityType || item?.entity_type || "";
      if (
        eventType !== "developer.ops.stabilization-handoff.confirm"
        && entityType !== "developer_ops_stabilization_handoff"
      ) {
        return null;
      }
      return buildStabilizationHandoffConfirmationPayload({
        id: item.id || null,
        eventType,
        actorType: item.actorType || item.actor_type || null,
        actorId: item.actorId || item.actor_id || null,
        entityType,
        entityId: item.entityId || item.entity_id || null,
        metadata,
        productCode: metadata.productCode || null,
        channel: metadata.channel || "stable",
        status: metadata.status || "confirmed",
        decision: metadata.decision || "confirmed",
        handoffFileName: metadata.handoffFileName || "developer-ops-stabilization-handoff.txt",
        confirmedAt: metadata.confirmedAt || item.createdAt || item.created_at || null,
        note: metadata.note || "",
        opsFiles: metadata.opsFiles || null,
        launchMainlineFiles: metadata.launchMainlineFiles || null,
        opsDownloads: metadata.opsDownloads || null,
        launchMainlineDownloads: metadata.launchMainlineDownloads || null,
        createdAt: item.createdAt || item.created_at || null
      });
    })
    .filter(Boolean)
    .sort((left, right) => snapshotDateMs(right.confirmedAt || right.createdAt) - snapshotDateMs(left.confirmedAt || left.createdAt))
    .slice(0, Math.max(1, Number(limit || 5)));
}

