function appendDeveloperOpsSteadyStateDutyActionLinksLines(lines, actionLinks = null, {
  title = "Steady-State Duty Action Links:"
} = {}) {
  if (!actionLinks || typeof actionLinks !== "object") {
    return;
  }
  lines.push(title);
  lines.push(
    `- status=${actionLinks.status || "-"}`
    + ` | readyForDuty=${actionLinks.readyForDuty === true}`
    + ` | actionCount=${actionLinks.actionCount ?? 0}`
    + ` | workspace=${actionLinks.workspaceLinkCount ?? 0}`
    + ` | control=${actionLinks.controlLinkCount ?? 0}`
    + ` | download=${actionLinks.downloadLinkCount ?? 0}`
    + ` | controlIntents=${actionLinks.controlIntentCount ?? 0}`
    + ` | executionPlans=${actionLinks.executionPlanCount ?? 0}`
    + ` | watchRecordDraft=${actionLinks.watchRecordDraftStatus || "-"}`
    + ` | records=${actionLinks.watchRecordDraftRecordCount ?? "-"}`
  );
  lines.push(
    `- actionLinksDownload=${actionLinks.actionLinksDownload?.fileName || "-"}`
    + ` | format=${actionLinks.actionLinksDownload?.format || "-"}`
    + ` | href=${actionLinks.actionLinksDownload?.href || "-"}`
  );
  if (actionLinks.productionSignoffPacket || actionLinks.launchDayWatchEntry) {
    lines.push(
      `- productionSignoffPacket=${actionLinks.productionSignoffPacket || "-"}`
      + ` | launchDayWatchEntry=${actionLinks.launchDayWatchEntry || "-"}`
    );
  }
  if (actionLinks.primaryAction) {
    lines.push(
      `- primaryAction=${actionLinks.primaryAction.label || actionLinks.primaryAction.key || "-"}`
      + ` | type=${actionLinks.primaryAction.type || "-"}`
      + ` | href=${actionLinks.primaryAction.href || "-"}`
    );
  }
  const appendLinks = (label, items = []) => {
    if (!Array.isArray(items) || !items.length) {
      return;
    }
    lines.push(`- ${label}:`);
    for (const item of items) {
      lines.push(
        `  - ${item.label || item.key || "-"}`
        + ` | priority=${item.priority || "-"}`
        + ` | source=${item.source || "-"}`
        + ` | href=${item.href || "-"}`
        + (item.fileName ? ` | file=${item.fileName}` : "")
        + (item.format ? ` | format=${item.format}` : "")
      );
    }
  };
  const appendIntents = (label, items = []) => {
    if (!Array.isArray(items) || !items.length) {
      return;
    }
    lines.push(`- ${label}:`);
    for (const item of items) {
      lines.push(
        `  - intent=${item.intent || "-"}`
        + ` | label=${item.label || item.key || "-"}`
        + ` | target=${item.targetType || "-"}`
        + ` | method=${item.method || "-"}`
        + ` | confirm=${item.requiresConfirmation === true}`
        + ` | plan=${item.executionPlan?.kind || "-"}:${item.executionPlan?.mode || "-"}`
        + ` | href=${item.href || "-"}`
        + (item.fileName ? ` | file=${item.fileName}` : "")
        + (item.format ? ` | format=${item.format}` : "")
      );
    }
  };
  const appendExecutionPlans = (label, items = []) => {
    const plans = Array.isArray(items)
      ? items.map((item) => item.executionPlan).filter(Boolean)
      : [];
    if (!plans.length) {
      return;
    }
    lines.push(`- ${label}:`);
    for (const plan of plans) {
      lines.push(
        `  - kind=${plan.kind || "-"}`
        + ` | mode=${plan.mode || "-"}`
        + ` | status=${plan.status || "-"}`
        + ` | method=${plan.method || "-"}`
        + ` | href=${plan.href || "-"}`
        + (plan.fileName ? ` | file=${plan.fileName}` : "")
        + (plan.format ? ` | format=${plan.format}` : "")
      );
    }
  };
  appendLinks("workspaceLinks", actionLinks.workspaceLinks);
  appendLinks("controlLinks", actionLinks.controlLinks);
  appendLinks("downloadLinks", actionLinks.downloadLinks);
  appendIntents("controlIntents", actionLinks.controlIntents);
  appendExecutionPlans("executionPlans", actionLinks.controlIntents);
}

