function appendDeveloperOpsLaunchOperationsHandoffSummaryLines(lines, summary = null, {
  title = "Launch Operations Handoff Summary:"
} = {}) {
  if (!summary || typeof summary !== "object") {
    return;
  }
  lines.push(title);
  lines.push(
    `- status=${summary.status || "-"}`
    + ` | evidence=${summary.evidenceChainStatus || "-"}`
    + ` | completed=${summary.evidenceCompletedStageCount ?? 0}/${summary.evidenceRequiredStageCount ?? 0}`
    + ` | latest=${summary.latestEvidenceStage?.key || "-"}`
  );
  lines.push(
    `- nextReview=${summary.nextReviewAction?.key || "-"}`
    + ` | stage=${summary.nextReviewAction?.stageKey || "-"}`
    + ` | summary=${summary.nextReviewAction?.summary || "-"}`
  );
  lines.push(
    `- watchRecordDraft=${summary.watchRecordDraftStatus || "-"}`
    + ` | records=${summary.watchRecordDraftRecordCount ?? "-"}`
  );
  lines.push(
    `- productionSignoffPacket=${summary.productionSignoffPacket || "-"}`
    + ` | launchDayWatchEntry=${summary.launchDayWatchEntry || "-"}`
  );
  lines.push(
    `- handoffDownload=${summary.handoffDownload?.fileName || "-"}`
    + ` | format=${summary.handoffDownload?.format || "-"}`
    + ` | href=${summary.handoffDownload?.href || "-"}`
  );
  const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(summary.launchOpsOverviewContext);
  if (launchOpsOverviewContext) {
    lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
    lines.push(
      `- launchOpsOverviewDownload=${formatLaunchHandoffDownloadText(
        buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext),
        { fileSeparator: " | " }
      )}`
    );
  }
  appendDeveloperOpsReceiptVisibilitySummaryLines(lines, summary.receiptVisibilitySummary);
  const checklist = Array.isArray(summary.handoffChecklist) ? summary.handoffChecklist : [];
  if (checklist.length) {
    lines.push("- checklist:");
    for (const item of checklist) {
      lines.push(
        `  - ${item.key || "-"}`
        + ` | status=${item.status || "-"}`
        + ` | ready=${item.ready === true}`
        + ` | audit=${item.auditLogId || "-"}`
        + ` | action=${item.action || "-"}`
        + ` | file=${item.fileName || "-"}`
      );
    }
  }
}

