function appendDeveloperOpsFirstWaveReadinessBridgeLines(lines = [], bridge = null, {
  title = "First-Wave Readiness Bridge:"
} = {}) {
  if (!Array.isArray(lines) || !bridge || typeof bridge !== "object") {
    return;
  }
  const segments = Array.isArray(bridge.segments) ? bridge.segments : [];
  lines.push(title);
  lines.push(
    `- status=${bridge.status || "-"}`
    + ` | gate=${bridge.currentGate || "-"}`
    + ` | ready=${bridge.readySegmentCount ?? 0}/${bridge.segmentCount ?? segments.length}`
    + ` | audit=${bridge.auditLogId || "-"}`
  );
  lines.push(
    `- nextAction=${bridge.nextAction?.key || bridge.nextAction?.operation || "-"}`
    + ` | operation=${bridge.nextAction?.operation || "-"}`
    + ` | confirm=${bridge.confirmation?.method || "POST"} ${bridge.confirmation?.endpoint || "-"}`
  );
  if (bridge.confirmation?.payloadTemplate) {
    const payloadTemplate = bridge.confirmation.payloadTemplate;
    lines.push(
      `- confirmationDraft=${payloadTemplate.decision || "-"}`
      + ` | file=${payloadTemplate.handoffFileName || "-"}`
      + ` | inventory=${payloadTemplate.inventoryStatus || "-"}`
      + ` | firstCards=${payloadTemplate.firstCardStatus || "-"}`
      + ` | firstRoundOps=${payloadTemplate.firstRoundOpsStatus || "-"}`
      + ` | receipt=${payloadTemplate.latestLaunchReceiptOperation || "-"}`
    );
  }
  lines.push(
    `- download=${bridge.downloads?.summary?.href || "-"}`
    + ` | json=${bridge.downloads?.json?.href || "-"}`
    + ` | checksums=${bridge.downloads?.checksums?.href || "-"}`
  );
  for (const segment of segments) {
    lines.push(`  - ${segment.key || "-"} | status=${segment.status || "-"} | ready=${segment.ready === true ? "yes" : "no"}`);
  }
}

function buildDeveloperOpsSummaryText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const launchReceiptFollowUpPriorities = summary.launchReceiptFollowUpPriorities || {};
  const launchReceiptNextFollowUp = summary.launchReceiptNextFollowUp || null;
  const launchReceiptNextFollowUpAction = launchReceiptNextFollowUp?.recommendedAction || null;
  const launchReceiptNextFollowUpWorkspace = launchReceiptNextFollowUpAction?.workspaceAction || null;
  const launchReceiptNextFollowUpDownload = launchReceiptNextFollowUp?.recommendedDownload || null;
  const initialLaunchOpsReadiness = summary.initialLaunchOpsReadiness || null;
  const overview = payload.overview || {};
  const routeReview = payload.routeReview || {};
  const launchReceiptAuditBackfill = Number(payload.auditLogs?.filters?.launchReceiptBackfill || 0);
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const lines = [
    "RockSolid Developer Ops Snapshot",
    `Generated At: ${payload.generatedAt || ""}`,
    `Developer: ${payload.developer?.username || "-"}`,
    `Actor: ${payload.actor?.username || "-"}`,
    `Actor Role: ${payload.actor?.role || "-"}`,
    `Accessible Projects: ${scope.accessibleProjectCount ?? 0}`,
    `Exported Projects: ${scope.exportedProjectCount ?? 0}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Username Filter: ${scope.username || "-"}`,
    `Search Filter: ${scope.search || "-"}`,
    `Audit Event Filter: ${scope.eventType || "-"}`,
    `Audit Actor Filter: ${scope.actorType || "-"}`,
    `Audit Entity Filter: ${scope.entityType || "-"}`,
    `Audit Limit: ${scope.auditLimit ?? 0}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    "",
    `Projects: ${summary.projects ?? 0}`,
    `Accounts: ${summary.accounts ?? 0}`,
    `Entitlements: ${summary.entitlements ?? 0}`,
    `Sessions: ${summary.sessions ?? 0}`,
    `Bindings: ${summary.bindings ?? 0}`,
    `Blocks: ${summary.blocks ?? 0}`,
    `Audit Logs: ${summary.auditLogs ?? 0}`,
    `Receipt Follow-up Count: ${summary.launchReceiptFollowUps ?? 0}`,
    `Receipt Follow-up Priorities: ${formatLaunchReceiptFollowUpPrioritySummary(launchReceiptFollowUpPriorities)}`,
    `Receipt Next Follow-up: ${formatLaunchReceiptNextFollowUp(launchReceiptNextFollowUp)}`,
    `Receipt Next Follow-up Action: ${launchReceiptNextFollowUpAction?.key || "-"} (${launchReceiptNextFollowUpAction?.operation || "-"})`,
    `Receipt Next Follow-up Workspace: ${launchReceiptNextFollowUpWorkspace?.label || "-"}@${launchReceiptNextFollowUpWorkspace?.autofocus || "-"}`,
    `Receipt Next Follow-up Download: ${launchReceiptNextFollowUpDownload?.fileName || "-"} (${launchReceiptNextFollowUpDownload?.format || "-"}) | href=${launchReceiptNextFollowUpDownload?.href || "-"}`
  ];
  appendFirstWaveAuditBackfillStatusText(lines, payload);

  if (initialLaunchOpsReadiness) {
    const gate = initialLaunchOpsReadiness.gate || {};
    lines.push("");
    lines.push("Initial Launch Ops Readiness:");
    lines.push(`- status: ${String(initialLaunchOpsReadiness.status || "unknown").toUpperCase()}`);
    lines.push(`- gate: ${String(gate.decision || "unknown").toUpperCase()} (canEnterInitialLaunch=${gate.canEnterInitialLaunch === true})`);
    lines.push(`- blockers: ${gate.blockerCount ?? (Array.isArray(gate.blockers) ? gate.blockers.length : 0)}`);
    lines.push(`- warnings: ${gate.warningCount ?? (Array.isArray(gate.warnings) ? gate.warnings.length : 0)}`);
    lines.push(`- requiredActions: ${gate.requiredActionCount ?? (Array.isArray(gate.requiredActions) ? gate.requiredActions.length : 0)}`);
    lines.push(`- headline: ${initialLaunchOpsReadiness.headline || "-"}`);
    lines.push(`- summary: ${initialLaunchOpsReadiness.summary || "-"}`);
    lines.push(`- followUps: ${initialLaunchOpsReadiness.followUpCount ?? 0}`);
    lines.push(`- next: ${formatLaunchReceiptNextFollowUp(initialLaunchOpsReadiness.nextFollowUp)}`);
    lines.push(`- workspace: ${initialLaunchOpsReadiness.primaryWorkspaceAction?.label || "-"}@${initialLaunchOpsReadiness.primaryWorkspaceAction?.autofocus || "-"}`);
    lines.push(`- download: ${initialLaunchOpsReadiness.primaryDownload?.fileName || "-"} (${initialLaunchOpsReadiness.primaryDownload?.format || "-"}) | href=${initialLaunchOpsReadiness.primaryDownload?.href || "-"}`);
    lines.push(`- firstLaunchHandoff: ${initialLaunchOpsReadiness.firstLaunchHandoffDownload?.fileName || "-"}`);
    if (initialLaunchOpsReadiness.firstWaveReadinessBridge) {
      lines.push("");
      appendDeveloperOpsFirstWaveReadinessBridgeLines(lines, initialLaunchOpsReadiness.firstWaveReadinessBridge);
    }
    if (initialLaunchOpsReadiness.launchDutyActionOrder) {
      lines.push("");
      appendDeveloperOpsLaunchDutyActionOrderLines(lines, initialLaunchOpsReadiness.launchDutyActionOrder);
    }
    const goNoGo = initialLaunchOpsReadiness.goNoGo || null;
    if (goNoGo) {
      lines.push("");
      lines.push("Initial Launch Go/No-Go:");
      lines.push(`- decision: ${goNoGo.label || String(goNoGo.decision || "unknown").toUpperCase()} (canEnterInitialLaunch=${goNoGo.canEnterInitialLaunch === true})`);
      lines.push(`- primaryBlocker: ${goNoGo.primaryBlockerStage || "-"}`);
      lines.push(`- nextOperation: ${goNoGo.nextOperation || "-"}`);
      lines.push(`- nextDownload: ${goNoGo.nextDownloadFileName || "-"} | href=${goNoGo.nextDownloadHref || "-"}`);
      lines.push(`- traceability: latestReceipt=${goNoGo.traceability?.latestReceiptOperation || "-"} | handoff=${goNoGo.traceability?.latestReceiptHandoffFileName || "-"} | opsIndex=${goNoGo.traceability?.opsHandoffIndex || "-"}`);
    }
    const contract = initialLaunchOpsReadiness.contract || null;
    if (contract) {
      lines.push("");
      lines.push("Initial Launch Contract:");
      lines.push(`- version: ${contract.version || "-"} | decision=${contract.label || String(contract.decision || "unknown").toUpperCase()} | status=${contract.status || "-"}`);
      lines.push(`- scope: project=${contract.projectCode || "-"} | channel=${contract.channel || "-"}`);
      lines.push(`- nextRequiredAction: stage=${contract.nextRequiredAction?.stage || "-"} | operation=${contract.nextRequiredAction?.operation || "-"} | download=${contract.nextRequiredAction?.downloadFileName || "-"} | href=${contract.nextRequiredAction?.downloadHref || "-"}`);
      lines.push(`- files: readiness=${contract.files?.initialLaunchOpsReadiness || "-"} | handoffIndex=${contract.files?.handoffIndex || "-"} | nextFollowUp=${contract.files?.launchReceiptNextFollowUp || "-"}`);
    }
    const operatorHeadline = initialLaunchOpsReadiness.operatorHeadline || null;
    if (operatorHeadline) {
      lines.push("");
      lines.push("Initial Launch Operator Headline:");
      lines.push(`- headline: ${operatorHeadline.headline || `${operatorHeadline.decisionLabel || "-"} | status=${operatorHeadline.status || "-"} | blocker=${operatorHeadline.primaryBlockerStage || "-"}`}`);
      lines.push(`- next: operation=${operatorHeadline.nextOperation || "-"} | download=${operatorHeadline.nextDownloadFileName || "-"} | href=${operatorHeadline.nextDownloadHref || "-"} | workspace=${operatorHeadline.workspaceHref || "-"}`);
      lines.push(`- handoff: ${operatorHeadline.handoffFileName || "-"} | readiness=${operatorHeadline.files?.readiness || "-"} | handoffIndex=${operatorHeadline.files?.handoffIndex || "-"}`);
    }
    appendInitialLaunchOperatorNextActionTextLines(lines, initialLaunchOpsReadiness.operatorNextAction || null, {
      labelCase: "lower"
    });
    appendInitialLaunchOperatorActionManifestTextLines(lines, initialLaunchOpsReadiness.operatorActionManifest || null, {
      labelCase: "lower"
    });
    if (Array.isArray(initialLaunchOpsReadiness.operatorActionReceipts) && initialLaunchOpsReadiness.operatorActionReceipts.length) {
      lines.push("");
      lines.push("Initial Launch Operator Action Receipts:");
      for (const item of initialLaunchOpsReadiness.operatorActionReceipts) {
        const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(item.launchOpsOverviewContext);
        lines.push(
          `- source=${item.source || "-"}`
          + ` | audit=${item.auditLogId || "-"}`
          + ` | operation=${item.operation || "-"}`
          + ` | decision=${item.decision || "-"}`
          + ` | action=${item.primaryActionKey || "-"}`
          + ` | next=${item.nextOperation || "-"}`
          + ` | download=${item.nextDownloadFileName || item.nextDownloadKey || "-"}`
          + ` | href=${item.nextDownloadHref || "-"}`
          + (launchOpsOverviewContext ? ` | ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}` : "")
        );
      }
    }
    const firstWaveHandoffConfirmation = initialLaunchOpsReadiness.firstWaveHandoffConfirmation || null;
    if (firstWaveHandoffConfirmation) {
      lines.push("");
      lines.push("First-Wave Handoff Confirmation:");
      lines.push(
        `- status=${firstWaveHandoffConfirmation.status || "-"}`
        + ` | audit=${firstWaveHandoffConfirmation.auditLogId || "-"}`
        + ` | decision=${firstWaveHandoffConfirmation.decision || "-"}`
        + ` | by=${firstWaveHandoffConfirmation.confirmedBy?.username || "-"}`
        + ` | file=${firstWaveHandoffConfirmation.handoffFileName || "-"}`
      );
      lines.push(
        `- inventory=${firstWaveHandoffConfirmation.sourceRecommendation?.inventoryStatus || "-"}`
        + ` | cards=${firstWaveHandoffConfirmation.sourceRecommendation?.firstCardStatus || "-"}`
        + ` | ops=${firstWaveHandoffConfirmation.sourceRecommendation?.firstRoundOpsStatus || "-"}`
        + ` | latestReceipt=${firstWaveHandoffConfirmation.sourceRecommendation?.latestLaunchReceiptOperation || "-"}`
      );
    }
    const firstWaveConfirmationChain = initialLaunchOpsReadiness.firstWaveConfirmationChain
      || initialLaunchOpsReadiness.traceability?.firstWaveConfirmationChain
      || firstWaveHandoffConfirmation?.firstWaveConfirmationChain
      || null;
    if (firstWaveConfirmationChain) {
      lines.push("");
      lines.push("First-Wave Confirmation Chain:");
      lines.push(
        `- status=${firstWaveConfirmationChain.status || "-"}`
        + ` | segments=${firstWaveConfirmationChain.confirmedSegmentCount ?? 0}/${firstWaveConfirmationChain.segmentCount ?? 0}`
        + ` | allConfirmed=${firstWaveConfirmationChain.allSegmentsConfirmed === true}`
        + ` | audit=${firstWaveConfirmationChain.auditLogId || "-"}`
      );
      lines.push(
        `- inventory=${firstWaveConfirmationChain.inventoryStatus || "-"}`
        + ` | firstCards=${firstWaveConfirmationChain.firstCardStatus || "-"}`
        + ` | firstRoundOps=${firstWaveConfirmationChain.firstRoundOpsStatus || "-"}`
        + ` | latestReceipt=${firstWaveConfirmationChain.latestLaunchReceiptOperation || "-"}`
      );
    }
    const stabilizationHandoff = initialLaunchOpsReadiness.stabilizationHandoff || null;
    if (stabilizationHandoff) {
      lines.push("");
      lines.push("Initial Launch Stabilization Handoff:");
      lines.push(
        `- version=${stabilizationHandoff.version || "-"}`
        + ` | status=${stabilizationHandoff.status || "-"}`
        + ` | decision=${stabilizationHandoff.decision || "-"}`
      );
      lines.push(
        `- latestReceipt=${stabilizationHandoff.latestLaunchReceipt?.operation || "-"}`
        + ` | postLaunchStatus=${stabilizationHandoff.latestLaunchReceipt?.postLaunchLifecycleStatus || "-"}`
        + ` | handoff=${stabilizationHandoff.latestLaunchReceipt?.handoffFileName || "-"}`
      );
      lines.push(
        `- latestOperator=${stabilizationHandoff.latestOperatorActionReceipt?.operation || "-"}`
        + ` | audit=${stabilizationHandoff.latestOperatorActionReceipt?.auditLogId || "-"}`
        + ` | next=${stabilizationHandoff.latestOperatorActionReceipt?.nextOperation || "-"}`
      );
      lines.push(
        `- nextAction=${stabilizationHandoff.nextAction?.operation || "-"}`
        + ` | download=${stabilizationHandoff.nextAction?.downloadFileName || stabilizationHandoff.nextAction?.downloadKey || "-"}`
        + ` | href=${stabilizationHandoff.nextAction?.downloadHref || "-"}`
        + ` | workspace=${stabilizationHandoff.nextAction?.workspaceHref || "-"}`
      );
      lines.push(
        `- files: readiness=${stabilizationHandoff.files?.readiness || "-"}`
        + ` | handoffIndex=${stabilizationHandoff.files?.handoffIndex || "-"}`
        + ` | nextFollowUp=${stabilizationHandoff.files?.nextFollowUp || "-"}`
        + ` | postLaunchIndex=${stabilizationHandoff.files?.postLaunchIndex || "-"}`
        + ` | routeMap=${stabilizationHandoff.files?.routeMap || "-"}`
      );
      const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(stabilizationHandoff.launchOpsOverviewContext);
      if (launchOpsOverviewContext) {
        lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
        lines.push(
          `- launchOpsOverviewDownload=${formatLaunchHandoffDownloadText(
            buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext),
            { fileSeparator: " | " }
          )}`
        );
      }
      const confirmation = stabilizationHandoff.confirmation || null;
      if (confirmation) {
        lines.push("");
        lines.push("Stabilization Handoff Confirmation:");
        lines.push(
          `- status=${confirmation.status || "-"}`
          + ` | audit=${confirmation.auditLogId || "-"}`
          + ` | decision=${confirmation.decision || "-"}`
          + ` | by=${confirmation.confirmedBy?.username || "-"}`
          + ` | file=${confirmation.handoffFileName || "-"}`
        );
      }
    }
    const launchDayWatchReceipt = initialLaunchOpsReadiness.launchDayWatchReceipt
      || initialLaunchOpsReadiness.traceability?.launchDayWatchReceipt
      || null;
    if (launchDayWatchReceipt) {
      lines.push("");
      lines.push("Launch-Day Watch Receipt:");
      lines.push(
        `- status=${launchDayWatchReceipt.status || "-"}`
        + ` | receiptRecorded=${launchDayWatchReceipt.receiptRecorded === true}`
        + ` | audit=${launchDayWatchReceipt.auditLogId || "-"}`
      );
      lines.push(
        `- latestReceipt=${launchDayWatchReceipt.operation || "-"}`
        + ` | handoff=${launchDayWatchReceipt.handoffFileName || "-"}`
        + ` | recordedAt=${launchDayWatchReceipt.recordedAt || "-"}`
      );
      lines.push(
        `- watchRecordDraft=${launchDayWatchReceipt.watchRecordDraftStatus || "-"}`
        + ` | records=${launchDayWatchReceipt.watchRecordDraftRecordCount ?? "-"}`
      );
      lines.push(
        `- action=${launchDayWatchReceipt.nextActionKey || "-"}`
        + ` | next=${launchDayWatchReceipt.nextOperation || "-"}`
        + ` | download=${launchDayWatchReceipt.primaryDownloadKey || "-"}`
      );
      lines.push(
        `- stabilizationNext=${launchDayWatchReceipt.stabilizationNextOperation || "-"}`
        + ` | postLaunchStatus=${launchDayWatchReceipt.postLaunchLifecycleStatus || "-"}`
      );
    }
    const stabilizationStatusReceipt = initialLaunchOpsReadiness.stabilizationStatusReceipt
      || initialLaunchOpsReadiness.traceability?.stabilizationStatusReceipt
      || null;
    if (stabilizationStatusReceipt) {
      lines.push("");
      lines.push("Stabilization Status Receipt:");
      lines.push(
        `- status=${stabilizationStatusReceipt.status || "-"}`
        + ` | confirmed=${stabilizationStatusReceipt.handoffConfirmed === true}`
        + ` | audit=${stabilizationStatusReceipt.confirmationAuditLogId || "-"}`
        + ` | followUps=${stabilizationStatusReceipt.followUpCount ?? 0}`
      );
      lines.push(
        `- latestReceipt=${stabilizationStatusReceipt.latestReceiptOperation || "-"}`
        + ` | watch=${stabilizationStatusReceipt.launchDayWatchStatus || "-"}`
        + ` | watchRecordDraft=${stabilizationStatusReceipt.watchRecordDraftStatus || "-"}`
        + ` | next=${stabilizationStatusReceipt.nextOperation || "-"}`
        + ` | steadyNext=${stabilizationStatusReceipt.steadyStateNextStep || "-"}`
      );
    }
    const operationalExceptionEntry = initialLaunchOpsReadiness.operationalExceptionEntry
      || initialLaunchOpsReadiness.traceability?.operationalExceptionEntry
      || null;
    if (operationalExceptionEntry) {
      lines.push("");
      lines.push("Operational Exception Entry:");
      lines.push(
        `- status=${operationalExceptionEntry.status || "-"}`
        + ` | severity=${operationalExceptionEntry.severity || "-"}`
        + ` | stage=${operationalExceptionEntry.stage || "-"}`
        + ` | operation=${operationalExceptionEntry.operation || "-"}`
      );
      lines.push(
        `- action=${operationalExceptionEntry.actionKey || "-"}`
        + ` | download=${operationalExceptionEntry.download?.fileName || operationalExceptionEntry.downloadKey || "-"}`
        + ` | workspace=${operationalExceptionEntry.workspaceAction?.label || "-"}@${operationalExceptionEntry.workspaceAction?.autofocus || "-"}`
      );
      lines.push(
        `- watch=${operationalExceptionEntry.launchDayWatchStatus || "-"}`
        + ` | watchRecordDraft=${operationalExceptionEntry.watchRecordDraftStatus || "-"}`
        + ` | stabilization=${operationalExceptionEntry.stabilizationStatus || "-"}`
        + ` | audit=${operationalExceptionEntry.confirmationAuditLogId || operationalExceptionEntry.latestReceiptAuditLogId || "-"}`
      );
    }
    const operationalExceptionCloseout = initialLaunchOpsReadiness.operationalExceptionCloseout
      || initialLaunchOpsReadiness.traceability?.operationalExceptionCloseout
      || null;
    if (operationalExceptionCloseout) {
      lines.push("");
      lines.push("Operational Exception Closeout:");
      lines.push(
        `- status=${operationalExceptionCloseout.status || "-"}`
        + ` | canClose=${operationalExceptionCloseout.canClose === true}`
        + ` | reviewRequired=${operationalExceptionCloseout.reviewRequired === true}`
        + ` | reasons=${operationalExceptionCloseout.blockingReasonCount ?? 0}`
      );
      lines.push(
        `- next=${operationalExceptionCloseout.nextOperation || "-"}`
        + ` | action=${operationalExceptionCloseout.nextActionKey || "-"}`
        + ` | download=${operationalExceptionCloseout.downloadKey || "-"}`
      );
      lines.push(
        `- actions: resolutionAction=${operationalExceptionCloseout.resolutionAction?.operation || "-"}`
        + ` | closeoutReview=${operationalExceptionCloseout.closeoutReviewAction?.operation || "-"}`
        + ` | endpoint=${operationalExceptionCloseout.closeoutReviewAction?.endpoint || "-"}`
      );
    }
    const closeoutReadinessSummary = initialLaunchOpsReadiness.closeoutReadinessSummary
      || initialLaunchOpsReadiness.traceability?.closeoutReadinessSummary
      || null;
    if (closeoutReadinessSummary) {
      lines.push("");
      appendDeveloperOpsCloseoutReadinessSummaryLines(lines, closeoutReadinessSummary);
    }
    const steadyStateOperationalReview = initialLaunchOpsReadiness.steadyStateOperationalReview || null;
    if (steadyStateOperationalReview) {
      lines.push("");
      appendDeveloperOpsSteadyStateOperationalReviewLines(lines, steadyStateOperationalReview);
    }
    const steadyStateExceptionDigest = initialLaunchOpsReadiness.steadyStateExceptionDigest || null;
    if (steadyStateExceptionDigest) {
      lines.push("");
      appendDeveloperOpsSteadyStateExceptionDigestLines(lines, steadyStateExceptionDigest);
    }
    const steadyStateHandoffBrief = initialLaunchOpsReadiness.steadyStateHandoffBrief || null;
    if (steadyStateHandoffBrief) {
      lines.push("");
      appendDeveloperOpsSteadyStateHandoffBriefLines(lines, steadyStateHandoffBrief);
    }
    const steadyStateDutyBoard = initialLaunchOpsReadiness.steadyStateDutyBoard || null;
    if (steadyStateDutyBoard) {
      lines.push("");
      appendDeveloperOpsSteadyStateDutyBoardLines(lines, steadyStateDutyBoard);
    }
    const steadyStateDutyActionLinks = initialLaunchOpsReadiness.steadyStateDutyActionLinks || null;
    if (steadyStateDutyActionLinks) {
      lines.push("");
      appendDeveloperOpsSteadyStateDutyActionLinksLines(lines, steadyStateDutyActionLinks);
    }
    const latestSteadyStateDutyPlanReceipt = initialLaunchOpsReadiness.latestSteadyStateDutyPlanReceipt || null;
    if (latestSteadyStateDutyPlanReceipt) {
      lines.push("");
      lines.push("Steady-State Duty Plan Receipts:");
      lines.push(
        `- status=${latestSteadyStateDutyPlanReceipt.status || "-"}`
        + ` | audit=${latestSteadyStateDutyPlanReceipt.auditLogId || "-"}`
        + ` | action=${latestSteadyStateDutyPlanReceipt.action || "-"}`
        + ` | intent=${latestSteadyStateDutyPlanReceipt.intent || "-"}`
        + ` | plan=${latestSteadyStateDutyPlanReceipt.planKind || "-"}:${latestSteadyStateDutyPlanReceipt.planMode || "-"}`
        + ` | file=${latestSteadyStateDutyPlanReceipt.fileName || latestSteadyStateDutyPlanReceipt.format || "-"}`
      );
      if (latestSteadyStateDutyPlanReceipt.receiptVisibility) {
        lines.push(
          `- receiptVisibility=${latestSteadyStateDutyPlanReceipt.receiptVisibility.status || "-"}`
          + ` | visibleIn=${Array.isArray(latestSteadyStateDutyPlanReceipt.receiptVisibility.visibleIn) ? latestSteadyStateDutyPlanReceipt.receiptVisibility.visibleIn.length : 0}`
          + ` | recovery=${latestSteadyStateDutyPlanReceipt.receiptVisibility.failureRecovery?.method || "-"} ${latestSteadyStateDutyPlanReceipt.receiptVisibility.failureRecovery?.route || "-"}`
        );
      }
    }
    const launchOperationsEvidenceChain = initialLaunchOpsReadiness.launchOperationsEvidenceChain || null;
    if (launchOperationsEvidenceChain) {
      lines.push("");
      appendDeveloperOpsLaunchOperationsEvidenceChainLines(lines, launchOperationsEvidenceChain);
    }
    const launchOperationsHandoffSummary = initialLaunchOpsReadiness.launchOperationsHandoffSummary || null;
    if (launchOperationsHandoffSummary) {
      lines.push("");
      appendDeveloperOpsLaunchOperationsHandoffSummaryLines(lines, launchOperationsHandoffSummary);
    }
    const launchOperationsDailyBrief = initialLaunchOpsReadiness.launchOperationsDailyBrief || null;
    if (launchOperationsDailyBrief) {
      lines.push("");
      appendDeveloperOpsLaunchOperationsDailyBriefLines(lines, launchOperationsDailyBrief);
    }
    const launchOperationsShiftActionPlan = initialLaunchOpsReadiness.launchOperationsShiftActionPlan || null;
    if (launchOperationsShiftActionPlan) {
      lines.push("");
      appendDeveloperOpsLaunchOperationsShiftActionPlanLines(lines, launchOperationsShiftActionPlan);
    }
    const launchOperationsOverviewStatus = initialLaunchOpsReadiness.launchOperationsOverviewStatus || null;
    if (launchOperationsOverviewStatus) {
      lines.push("");
      appendDeveloperOpsLaunchOperationsOverviewStatusLines(lines, launchOperationsOverviewStatus);
    }
    if (Array.isArray(initialLaunchOpsReadiness.nextSteps) && initialLaunchOpsReadiness.nextSteps.length) {
      lines.push("- nextSteps:");
      for (const item of initialLaunchOpsReadiness.nextSteps) {
        lines.push(`  - ${item}`);
      }
    }
    const traceability = initialLaunchOpsReadiness.traceability || null;
    if (traceability) {
      const latestLaunchReceipt = traceability.latestLaunchReceipt || {};
      const nextFollowUp = traceability.nextFollowUp || {};
      const opsFiles = traceability.opsFiles || {};
      const launchMainlineFiles = traceability.launchMainlineFiles || {};
      lines.push("");
      lines.push("Initial Launch Ops Traceability:");
      lines.push(`- latestReceipt=${latestLaunchReceipt.operation || "-"} | handoff=${latestLaunchReceipt.handoffFileName || "-"} | evidenceNext=${latestLaunchReceipt.productionEvidenceNextOperation || "-"} | lifecycleNext=${latestLaunchReceipt.postLaunchLifecycleNextOperation || "-"}`);
      lines.push(
        `- nextFollowUp=${opsFiles.launchReceiptNextFollowUp || "-"}`
        + ` | operation=${nextFollowUp.operationToRecord || "-"}`
        + ` | action=${nextFollowUp.actionKey || "-"}`
        + ` | download=${nextFollowUp.downloadFileName || nextFollowUp.recommendedDownload?.fileName || nextFollowUp.downloadKey || "-"}`
        + ` | href=${nextFollowUp.downloadHref || nextFollowUp.recommendedDownload?.href || "-"}`
      );
      lines.push(`- opsIndex=${opsFiles.handoffIndex || "-"} | readiness=${opsFiles.initialLaunchOpsReadiness || "-"} | followUpsCsv=${opsFiles.launchReceiptFollowUpsCsv || "-"}`);
      lines.push(`- postLaunchIndex=${launchMainlineFiles.postLaunchHandoffIndex || "-"} | routeMap=${launchMainlineFiles.handoffDownloadRoutes || "-"} | checksums=${launchMainlineFiles.checksums || "-"} | zip=${launchMainlineFiles.zip || "-"}`);
      const confirmation = traceability.stabilizationHandoffConfirmation || null;
      if (confirmation) {
        const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(confirmation.launchOpsOverviewContext);
        lines.push(
          `- stabilizationConfirmation=${confirmation.status || "-"}`
          + ` | audit=${confirmation.auditLogId || "-"}`
          + ` | decision=${confirmation.decision || "-"}`
          + ` | by=${confirmation.confirmedBy?.username || "-"}`
          + (launchOpsOverviewContext ? ` | ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}` : "")
        );
      }
      const firstWaveConfirmation = traceability.firstWaveHandoffConfirmation || null;
      if (firstWaveConfirmation) {
        lines.push(`- firstWaveConfirmation=${firstWaveConfirmation.status || "-"} | audit=${firstWaveConfirmation.auditLogId || "-"} | decision=${firstWaveConfirmation.decision || "-"} | by=${firstWaveConfirmation.confirmedBy?.username || "-"}`);
      }
    }
    const stagingArchive = initialLaunchOpsReadiness.stagingLaunchDutyArchive || null;
    if (stagingArchive) {
      lines.push("");
      lines.push("Staging Launch-Duty Archive:");
      lines.push(
        `- status=${stagingArchive.status || "-"}`
        + ` | archiveRoot=${stagingArchive.archiveRoot || "-"}`
        + ` | launchDutyArchiveIndex=${stagingArchive.files?.launchDutyArchiveIndex || "-"}`
      );
      const packetCompleteness = stagingArchive.packetCompleteness || null;
      if (packetCompleteness && typeof packetCompleteness === "object") {
        const expectedCount = Number.isFinite(Number(packetCompleteness.expectedCount))
          ? Number(packetCompleteness.expectedCount)
          : 0;
        const listedCount = Number.isFinite(Number(packetCompleteness.listedCount))
          ? Number(packetCompleteness.listedCount)
          : 0;
        const missingKeys = Array.isArray(packetCompleteness.missingKeys) && packetCompleteness.missingKeys.length
          ? packetCompleteness.missingKeys.join(",")
          : "-";
        lines.push(`- packetCompleteness=${packetCompleteness.status || "-"} | listed=${listedCount}/${expectedCount} | missing=${missingKeys}`);
      }
      lines.push(`- command=${stagingArchive.commands?.profileDrivenDryRun || "-"}`);
    }
  }

  if (overview && typeof overview === "object" && Object.keys(overview).length) {
    lines.push("");
    lines.push(`Overview Status: ${overview.status || "-"}`);
    lines.push(`Overview Headline: ${overview.headline || "-"}`);
    lines.push(`Latest Audit At: ${overview.latestAuditAt || "-"}`);
    appendFirstWaveRuntimeEvidenceLines(lines, overview);
    if (Array.isArray(overview.highlights) && overview.highlights.length) {
      lines.push("Highlights:");
      for (const item of overview.highlights) {
        lines.push(`- ${item}`);
      }
    }
    if (Array.isArray(overview.topAuditEvents) && overview.topAuditEvents.length) {
      lines.push("Top Audit Events:");
      for (const item of overview.topAuditEvents) {
        lines.push(`- ${item.eventType || "-"} x${item.count ?? 0}`);
      }
    }
    if (Array.isArray(overview.latestLaunchReceipts) && overview.latestLaunchReceipts.length) {
      lines.push("Latest Launch Receipts:");
      for (const item of overview.latestLaunchReceipts) {
        lines.push(`- ${item.operationLabel || item.operation || "-"} | project=${item.productCode || "-"} | channel=${item.channel || "-"} | gate=${item.mainlineGateStatus || "-"} | evidenceRemaining=${item.productionEvidenceRemainingCount ?? "-"} | readiness=${item.operationalReadinessStatus || "-"} | watchRecordDraft=${item.operationalReadinessWatchRecordDraftStatus || "-"} | readinessNext=${item.operationalReadinessNextOperation || "-"} | operatorNext=${item.initialLaunchOperatorNextOperation || "-"} | handoff=${item.handoffFileName || "-"}`);
        appendDeveloperOpsReceiptVisibilityText(lines, item);
      }
    }
    if (Array.isArray(overview.latestFirstWaveHandoffConfirmations) && overview.latestFirstWaveHandoffConfirmations.length) {
      lines.push("Latest First-Wave Handoff Confirmations:");
      for (const item of overview.latestFirstWaveHandoffConfirmations) {
        lines.push(`- ${item.status || "-"} | project=${item.productCode || "-"} | channel=${item.channel || "-"} | audit=${item.auditLogId || "-"} | file=${item.handoffFileName || "-"}`);
      }
    }
    if (Array.isArray(overview.launchReceiptFollowUps) && overview.launchReceiptFollowUps.length) {
      lines.push("Launch Receipt Follow-ups:");
      for (const item of overview.launchReceiptFollowUps) {
        const recommendedDownload = item.recommendedDownload && typeof item.recommendedDownload === "object"
          ? item.recommendedDownload
          : buildDeveloperOpsLaunchReceiptFollowUpDownload(item, scope);
        lines.push(
          `- [${item.priority || "-"}][${item.stage || "-"}] ${item.title || "-"}`
          + ` | project=${item.productCode || "-"}`
          + ` | channel=${item.channel || "-"}`
          + ` | action=${item.actionKey || "-"}`
          + ` | operation=${item.operationToRecord || "-"}`
          + ` | download=${item.downloadKey || recommendedDownload?.key || "-"}`
          + ` | file=${item.downloadFileName || recommendedDownload?.fileName || "-"}`
          + ` | format=${item.downloadFormat || recommendedDownload?.format || "-"}`
          + ` | href=${item.downloadHref || recommendedDownload?.href || "-"}`
          + ` | handoff=${item.handoffFileName || "-"}`
          + ` | readiness=${item.operationalReadinessStatus || "-"}`
          + ` | watchRecordDraft=${item.operationalReadinessWatchRecordDraftStatus || "-"}`
          + ` | readinessAction=${item.operationalReadinessNextActionKey || "-"}`
          + ` | readinessNext=${item.operationalReadinessNextOperation || "-"}`
          + ` | ${item.summary || "-"}`
        );
      }
    }
    if (Array.isArray(overview.topReasons) && overview.topReasons.length) {
      lines.push("Top Reasons:");
      for (const item of overview.topReasons) {
        lines.push(`- ${item.reason || "-"} x${item.count ?? 0}`);
      }
    }
    if (Array.isArray(overview.focusUsernames) && overview.focusUsernames.length) {
      lines.push("Focus Usernames:");
      for (const item of overview.focusUsernames) {
        lines.push(`- ${item.username || "-"} x${item.count ?? 0}`);
      }
    }
    if (Array.isArray(overview.focusFingerprints) && overview.focusFingerprints.length) {
      lines.push("Focus Fingerprints:");
      for (const item of overview.focusFingerprints) {
        lines.push(`- ${item.fingerprint || "-"} x${item.count ?? 0}`);
      }
    }
    if (Array.isArray(overview.focusAccounts) && overview.focusAccounts.length) {
      lines.push("Focus Account Details:");
      for (const item of overview.focusAccounts) {
        lines.push(`- ${item.username || "-"} @ ${item.productCode || "-"} | issues=${item.issueCount ?? 0} | severity=${item.severity || "-"} | account=${item.accountId || "-"} | control=${item.recommendedControl?.label || "-"} | next=${item.actionHint || "-"}`);
      }
    }
    if (Array.isArray(overview.focusSessions) && overview.focusSessions.length) {
      lines.push("Focus Sessions:");
      for (const item of overview.focusSessions) {
        lines.push(`- ${item.sessionId || "-"} | ${item.username || "-"} @ ${item.productCode || "-"} | ${item.status || "-"} | severity=${item.severity || "-"} | control=${item.recommendedControl?.label || "-"} | ${item.reason || "-"} | next=${item.actionHint || "-"}`);
      }
    }
    if (Array.isArray(overview.focusDevices) && overview.focusDevices.length) {
      lines.push("Focus Devices:");
      for (const item of overview.focusDevices) {
        lines.push(`- ${item.fingerprint || "-"} @ ${item.productCode || "-"} | ${item.kind || "-"} | ${item.status || "-"} | severity=${item.severity || "-"} | control=${item.recommendedControl?.label || "-"} | ${item.reason || "-"} | next=${item.actionHint || "-"}`);
      }
    }
    if (routeReview.active) {
      lines.push(`Route Review Focus: ${routeReview.focus || "-"}`);
      lines.push(`Route Review Counts: accounts:${routeReview.matchedCounts?.accounts ?? 0} | entitlements:${routeReview.matchedCounts?.entitlements ?? 0} | sessions:${routeReview.matchedCounts?.sessions ?? 0} | devices:${routeReview.matchedCounts?.devices ?? 0} | audit:${routeReview.matchedCounts?.audit ?? 0}`);
      if (Array.isArray(routeReview.highlightedEvents) && routeReview.highlightedEvents.length) {
        lines.push(`Route Review Events: ${routeReview.highlightedEvents.join(", ")}`);
      }
      if (routeReview.primaryMatch) {
        lines.push("Route Review Primary Match:");
        lines.push(`- ${routeReview.primaryMatch.title || "-"} | ${routeReview.primaryMatch.summary || "-"} | action=${routeReview.primaryMatch.routeActionLabel || routeReview.primaryMatch.routeAction || "-"} | control=${routeReview.primaryMatch.recommendedControl?.label || "-"}`);
      }
      if (routeReview.nextMatch) {
        lines.push("Route Review Next Match:");
        lines.push(`- ${routeReview.nextMatch.title || "-"} | ${routeReview.nextMatch.summary || "-"} | action=${routeReview.nextMatch.routeActionLabel || routeReview.nextMatch.routeAction || "-"} | control=${routeReview.nextMatch.recommendedControl?.label || "-"}`);
      }
      if (Array.isArray(routeReview.remainingMatches) && routeReview.remainingMatches.length) {
        lines.push("Route Review Remaining Matches:");
        routeReview.remainingMatches.slice(0, 5).forEach((item) => {
          lines.push(`- ${item.title || "-"} | ${item.summary || "-"} | action=${item.routeActionLabel || item.routeAction || "-"} | control=${item.recommendedControl?.label || "-"}`);
        });
      }
      if (routeReview.mainlineHandoff?.workspaceAction?.key) {
        const mainlineHandoff = routeReview.mainlineHandoff;
        const workspaceAction = mainlineHandoff.workspaceAction || {};
        const handoffDownloads = mainlineHandoff.downloads || {};
        const summaryDownload = handoffDownloads.summary || mainlineHandoff.recommendedDownload || null;
        lines.push("Launch Mainline Handoff:");
        lines.push(`- workspace=${workspaceAction.label || "-"}@${workspaceAction.autofocus || "-"} | href=${workspaceAction.href || "-"}`);
        lines.push(`- summary=${formatLaunchHandoffDownloadText(summaryDownload, { fileSeparator: " | " })}`);
        lines.push(`- rehearsal=${formatLaunchHandoffDownloadText(handoffDownloads.rehearsalGuide, { fileSeparator: " | " })}`);
        lines.push(`- firstLaunch=${formatLaunchHandoffDownloadText(handoffDownloads.firstLaunchHandoff, { fileSeparator: " | " })}`);
      }
    }
    appendSnapshotEscalationSummaryLines(lines, overview);
    appendSnapshotQueueSummaryLines(lines, overview);
  }

  if (Array.isArray(payload.projects) && payload.projects.length) {
    lines.push("");
    lines.push("Projects:");
    for (const item of payload.projects) {
      lines.push(`- ${item.code || "-"} (${item.name || ""}) [${item.status || "unknown"}]`);
    }
  }

  return lines.join("\n");
}

function buildDeveloperOpsLaunchReceiptNextFollowUpText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const overview = payload.overview || {};
  const item = summary.launchReceiptNextFollowUp
    || buildLaunchReceiptNextFollowUp(overview.launchReceiptFollowUps || []);
  const recommendedAction = item?.recommendedAction
    || buildDeveloperOpsLaunchReceiptNextFollowUpAction(item);
  const recommendedWorkspace = recommendedAction?.workspaceAction || null;
  const recommendedDownload = item?.recommendedDownload
    || buildDeveloperOpsLaunchReceiptNextFollowUpDownload(scope, item);
  const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(item?.launchOpsOverviewContext);
  const launchOpsOverviewDownload = buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext);
  const launchReceiptAuditBackfill = Number(
    summary.launchReceiptAuditBackfill
    ?? payload.auditLogs?.filters?.launchReceiptBackfill
    ?? 0
  );
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const latestLaunchReceipts = Array.isArray(overview.latestLaunchReceipts)
    ? overview.latestLaunchReceipts
    : [];
  const receiptVisibilitySource = latestLaunchReceipts.find((receipt) => (
    receipt?.receiptVisibility
      && item?.handoffFileName
      && receipt.handoffFileName === item.handoffFileName
  )) || latestLaunchReceipts.find((receipt) => (
    receipt?.receiptVisibility
      && (!item?.operation || receipt.operation === item.operation)
      && (!item?.productCode || receipt.productCode === item.productCode)
      && (!item?.channel || receipt.channel === item.channel)
  )) || latestLaunchReceipts.find((receipt) => receipt?.receiptVisibility);
  const lines = [
    "RockSolid Developer Ops Launch Receipt Next Follow-up",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Receipt Follow-up Count: ${summary.launchReceiptFollowUps ?? 0}`,
    `Receipt Follow-up Priorities: ${formatLaunchReceiptFollowUpPrioritySummary(summary.launchReceiptFollowUpPriorities || {})}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    ""
  ];

  if (!item) {
    lines.push("No launch receipt follow-up is queued for this scoped snapshot.");
    return lines.join("\n");
  }

  lines.push(`Priority: ${String(item.priority || "secondary").toUpperCase()}`);
  lines.push(`Stage: ${item.stage || "-"}`);
  lines.push(`Title: ${item.title || "-"}`);
  lines.push(`Summary: ${item.summary || "-"}`);
  lines.push(`Project Code: ${item.productCode || "-"}`);
  lines.push(`Channel: ${item.channel || "-"}`);
  lines.push(`Operation: ${item.operation || "-"}`);
  lines.push(`Operation To Record: ${item.operationToRecord || "-"}`);
  lines.push(`Action Key: ${item.actionKey || "-"}`);
  lines.push(`Download Key: ${item.downloadKey || "-"}`);
  lines.push(`Handoff File: ${item.handoffFileName || "-"}`);
  lines.push(`Mainline Gate: ${item.mainlineGateStatus || "-"}`);
  lines.push(`Operational Readiness: ${item.operationalReadinessStatus || "-"}`);
  lines.push(`Operational Readiness Action: ${item.operationalReadinessNextActionKey || "-"}`);
  lines.push(`Operational Readiness Next: ${item.operationalReadinessNextOperation || "-"}`);
  lines.push(`Operational Readiness Download: ${item.operationalReadinessPrimaryDownloadKey || "-"}`);
  lines.push(`Created At: ${item.createdAt || "-"}`);
  lines.push(`Recommended Action: ${recommendedAction?.key || "-"}`);
  lines.push(`Action Operation: ${recommendedAction?.operation || "-"}`);
  lines.push(`Action Source: ${recommendedAction?.source || "-"}`);
  lines.push(`Workspace Action: ${recommendedWorkspace?.label || "-"}`);
  lines.push(`Workspace Autofocus: ${recommendedWorkspace?.autofocus || "-"}`);
  lines.push(`Workspace Href: ${recommendedWorkspace?.href || "-"}`);
  lines.push(`Download File: ${recommendedDownload?.fileName || "-"}`);
  lines.push(`Download Format: ${recommendedDownload?.format || "-"}`);
  lines.push(`Download Href: ${recommendedDownload?.href || "-"}`);
  if (launchOpsOverviewContext) {
    lines.push("");
    lines.push("Launch Ops Overview Context:");
    lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
    lines.push(`- download: ${formatLaunchHandoffDownloadText(launchOpsOverviewDownload, { fileSeparator: " | " })}`);
  }
  if (receiptVisibilitySource) {
    lines.push("");
    appendDeveloperOpsReceiptVisibilityText(lines, receiptVisibilitySource);
  }
  lines.push("");
  lines.push("Operator Hand-off:");
  lines.push(`- Next: ${formatLaunchReceiptNextFollowUp(item)}`);
  lines.push("- Use the action key in Developer Ops or the download key in launch mainline handoff when you need the full artifact.");
  return lines.join("\n");
}

function buildDeveloperOpsStagingLaunchDutyArchiveText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const archive = readiness.stagingLaunchDutyArchive || buildDeveloperOpsStagingLaunchDutyArchive(scope);
  const launchReceiptAuditBackfill = Number(
    summary.launchReceiptAuditBackfill
    ?? payload.auditLogs?.filters?.launchReceiptBackfill
    ?? 0
  );
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const lines = [
    "RockSolid Developer Ops Staging Launch-Duty Archive",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Channel: ${archive.channel || scope.channel || "stable"}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    ""
  ];
  appendDeveloperOpsStagingLaunchDutyArchiveLines(lines, archive);
  if (readiness.launchDutyActionOrder) {
    lines.push("");
    appendDeveloperOpsLaunchDutyActionOrderLines(lines, readiness.launchDutyActionOrder);
  }
  lines.push("");
  lines.push("Operator Order:");
  lines.push("- Generate this bridge from Developer Ops before the real staging rehearsal.");
  lines.push("- Run profileDrivenDryRun with real non-secret staging inputs and secret env vars set outside the profile.");
  lines.push("- Archive staging-launch-duty-archive-index.json beside the listed packet files before the closeout reload.");
  lines.push("- Keep this bridge with handoff-index.txt so API reviewers and staging operators use the same product/channel archive paths.");
  return lines.join("\n");
}

function buildDeveloperOpsInitialLaunchOpsReadinessText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const gate = readiness.gate || {};
  const launchReceiptAuditBackfill = Number(
    summary.launchReceiptAuditBackfill
    ?? payload.auditLogs?.filters?.launchReceiptBackfill
    ?? 0
  );
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const lines = [
    "RockSolid Developer Ops Initial Launch Readiness",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    `Status: ${String(readiness.status || "unknown").toUpperCase()}`,
    `Gate Decision: ${String(gate.decision || "unknown").toUpperCase()}`,
    `Can Enter Initial Launch: ${gate.canEnterInitialLaunch === true ? "yes" : "no"}`,
    `Gate Severity: ${String(gate.severity || "unknown").toUpperCase()}`,
    `Gate Blockers: ${gate.blockerCount ?? (Array.isArray(gate.blockers) ? gate.blockers.length : 0)}`,
    `Gate Warnings: ${gate.warningCount ?? (Array.isArray(gate.warnings) ? gate.warnings.length : 0)}`,
    `Required Action Count: ${gate.requiredActionCount ?? (Array.isArray(gate.requiredActions) ? gate.requiredActions.length : 0)}`,
    `Headline: ${readiness.headline || "-"}`,
    `Summary: ${readiness.summary || "-"}`,
    `Follow-up Count: ${readiness.followUpCount ?? 0}`,
    `Follow-up Priorities: ${formatLaunchReceiptFollowUpPrioritySummary(readiness.priorities || {})}`,
    `Latest Receipt: ${readiness.latestReceipt?.operationLabel || readiness.latestReceipt?.operation || "-"} | gate=${readiness.latestReceipt?.mainlineGateStatus || "-"} | handoff=${readiness.latestReceipt?.handoffFileName || "-"}`,
    `Next Follow-up: ${formatLaunchReceiptNextFollowUp(readiness.nextFollowUp)}`,
    `Primary Workspace: ${readiness.primaryWorkspaceAction?.label || "-"} | focus=${readiness.primaryWorkspaceAction?.autofocus || "-"} | href=${readiness.primaryWorkspaceAction?.href || "-"}`,
    `Primary Download: ${readiness.primaryDownload?.fileName || "-"} | format=${readiness.primaryDownload?.format || "-"} | href=${readiness.primaryDownload?.href || "-"}`,
    `First Launch Handoff: ${readiness.firstLaunchHandoffDownload?.fileName || "-"} | href=${readiness.firstLaunchHandoffDownload?.href || "-"}`,
    ""
  ];
  if (readiness.firstWaveReadinessBridge) {
    appendDeveloperOpsFirstWaveReadinessBridgeLines(lines, readiness.firstWaveReadinessBridge);
    lines.push("");
  }
  if (readiness.launchDutyActionOrder) {
    appendDeveloperOpsLaunchDutyActionOrderLines(lines, readiness.launchDutyActionOrder);
    lines.push("");
  }
  if (readiness.stagingLaunchDutyArchive) {
    appendDeveloperOpsStagingLaunchDutyArchiveLines(lines, readiness.stagingLaunchDutyArchive);
    lines.push("");
  }
  const contract = readiness.contract || null;
  if (contract) {
    lines.push("Contract:");
    lines.push(`- Version: ${contract.version || "-"}`);
    lines.push(`- Decision: ${contract.label || String(contract.decision || "unknown").toUpperCase()} (canEnterInitialLaunch=${contract.canEnterInitialLaunch === true})`);
    lines.push(`- Scope: project=${contract.projectCode || "-"} | channel=${contract.channel || "-"}`);
    lines.push(`- Next Required Action: ${contract.nextRequiredAction?.stage || "-"} | operation=${contract.nextRequiredAction?.operation || "-"} | download=${contract.nextRequiredAction?.downloadFileName || "-"} | href=${contract.nextRequiredAction?.downloadHref || "-"}`);
    lines.push(`- Files: readiness=${contract.files?.initialLaunchOpsReadiness || "-"} | handoffIndex=${contract.files?.handoffIndex || "-"} | nextFollowUp=${contract.files?.launchReceiptNextFollowUp || "-"}`);
    lines.push("");
  }
  const operatorHeadline = readiness.operatorHeadline || null;
  if (operatorHeadline) {
    lines.push("Operator Headline:");
    lines.push(`- Headline: ${operatorHeadline.headline || `${operatorHeadline.decisionLabel || "-"} | status=${operatorHeadline.status || "-"} | blocker=${operatorHeadline.primaryBlockerStage || "-"}`}`);
    lines.push(`- Next: operation=${operatorHeadline.nextOperation || "-"} | download=${operatorHeadline.nextDownloadFileName || "-"} | href=${operatorHeadline.nextDownloadHref || "-"} | workspace=${operatorHeadline.workspaceHref || "-"}`);
    lines.push(`- Handoff: ${operatorHeadline.handoffFileName || "-"} | readiness=${operatorHeadline.files?.readiness || "-"} | handoffIndex=${operatorHeadline.files?.handoffIndex || "-"}`);
    lines.push("");
  }
  appendInitialLaunchOperatorNextActionTextLines(lines, readiness.operatorNextAction || null, {
    title: "Operator Next Action:"
  });
  appendInitialLaunchOperatorActionManifestTextLines(lines, readiness.operatorActionManifest || null, {
    title: "Operator Action Manifest:"
  });
  const stabilizationHandoff = readiness.stabilizationHandoff || null;
  if (stabilizationHandoff) {
    lines.push("Stabilization Handoff:");
    lines.push(`- Version: ${stabilizationHandoff.version || "-"}`);
    lines.push(`- Status: ${stabilizationHandoff.status || "-"} | decision=${stabilizationHandoff.decision || "-"}`);
    lines.push(`- Latest Receipt: ${stabilizationHandoff.latestLaunchReceipt?.operation || "-"} | handoff=${stabilizationHandoff.latestLaunchReceipt?.handoffFileName || "-"}`);
    lines.push(`- Post-Launch: status=${stabilizationHandoff.latestLaunchReceipt?.postLaunchLifecycleStatus || "-"} | next=${stabilizationHandoff.latestLaunchReceipt?.postLaunchLifecycleNextOperation || "-"}`);
    lines.push(`- Latest Operator: ${stabilizationHandoff.latestOperatorActionReceipt?.operation || "-"} | audit=${stabilizationHandoff.latestOperatorActionReceipt?.auditLogId || "-"} | next=${stabilizationHandoff.latestOperatorActionReceipt?.nextOperation || "-"}`);
    lines.push(`- Next Action: ${stabilizationHandoff.nextAction?.operation || "-"} | download=${stabilizationHandoff.nextAction?.downloadFileName || stabilizationHandoff.nextAction?.downloadKey || "-"} | href=${stabilizationHandoff.nextAction?.downloadHref || "-"} | workspace=${stabilizationHandoff.nextAction?.workspaceHref || "-"}`);
    lines.push(`- Files: readiness=${stabilizationHandoff.files?.readiness || "-"} | handoffIndex=${stabilizationHandoff.files?.handoffIndex || "-"} | nextFollowUp=${stabilizationHandoff.files?.nextFollowUp || "-"} | postLaunchIndex=${stabilizationHandoff.files?.postLaunchIndex || "-"}`);
    const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(stabilizationHandoff.launchOpsOverviewContext);
    if (launchOpsOverviewContext) {
      lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
      lines.push(`- download: ${formatLaunchHandoffDownloadText(buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext), { fileSeparator: " | " })}`);
    }
    if (Array.isArray(stabilizationHandoff.checklist) && stabilizationHandoff.checklist.length) {
      lines.push("- Checklist:");
      for (const item of stabilizationHandoff.checklist) {
        lines.push(`  - ${item}`);
      }
    }
    lines.push("");
  }
  const launchDayWatchReceipt = readiness.launchDayWatchReceipt
    || readiness.traceability?.launchDayWatchReceipt
    || null;
  if (launchDayWatchReceipt) {
    lines.push("Launch-Day Watch Receipt:");
    lines.push(`- Status: ${launchDayWatchReceipt.status || "-"} | receiptRecorded=${launchDayWatchReceipt.receiptRecorded === true}`);
    lines.push(`- Watch Record Draft: ${launchDayWatchReceipt.watchRecordDraftStatus || "-"} | records=${launchDayWatchReceipt.watchRecordDraftRecordCount ?? "-"}`);
    lines.push(`- Latest Receipt: ${launchDayWatchReceipt.operation || "-"} | handoff=${launchDayWatchReceipt.handoffFileName || "-"} | recordedAt=${launchDayWatchReceipt.recordedAt || "-"}`);
    lines.push(`- Next: action=${launchDayWatchReceipt.nextActionKey || "-"} | operation=${launchDayWatchReceipt.nextOperation || "-"} | download=${launchDayWatchReceipt.primaryDownloadKey || "-"}`);
    lines.push(`- Stabilization: status=${launchDayWatchReceipt.stabilizationStatus || "-"} | next=${launchDayWatchReceipt.stabilizationNextOperation || "-"} | postLaunch=${launchDayWatchReceipt.postLaunchLifecycleStatus || "-"}`);
    lines.push(`- Files: readiness=${launchDayWatchReceipt.operatorHandoffFiles?.readiness || "-"} | handoffIndex=${launchDayWatchReceipt.operatorHandoffFiles?.handoffIndex || "-"} | nextFollowUp=${launchDayWatchReceipt.operatorHandoffFiles?.nextFollowUp || "-"} | postLaunchIndex=${launchDayWatchReceipt.operatorHandoffFiles?.postLaunchIndex || "-"}`);
    lines.push("");
  }
  const stabilizationStatusReceipt = readiness.stabilizationStatusReceipt
    || readiness.traceability?.stabilizationStatusReceipt
    || null;
  if (stabilizationStatusReceipt) {
    lines.push("Stabilization Status Receipt:");
    lines.push(`- Status: ${stabilizationStatusReceipt.status || "-"} | confirmed=${stabilizationStatusReceipt.handoffConfirmed === true} | audit=${stabilizationStatusReceipt.confirmationAuditLogId || "-"}`);
    lines.push(`- Latest Receipt: ${stabilizationStatusReceipt.latestReceiptOperation || "-"} | watch=${stabilizationStatusReceipt.launchDayWatchStatus || "-"} | watchRecordDraft=${stabilizationStatusReceipt.watchRecordDraftStatus || "-"} | postLaunch=${stabilizationStatusReceipt.postLaunchLifecycleStatus || "-"}`);
    lines.push(`- Next: action=${stabilizationStatusReceipt.nextActionKey || "-"} | operation=${stabilizationStatusReceipt.nextOperation || "-"} | download=${stabilizationStatusReceipt.downloadKey || "-"}`);
    lines.push(`- Steady State: next=${stabilizationStatusReceipt.steadyStateNextStep || "-"} | stabilizationNext=${stabilizationStatusReceipt.stabilizationNextOperation || "-"} | followUps=${stabilizationStatusReceipt.followUpCount ?? 0}`);
    lines.push(`- Files: readiness=${stabilizationStatusReceipt.operatorHandoffFiles?.readiness || "-"} | handoffIndex=${stabilizationStatusReceipt.operatorHandoffFiles?.handoffIndex || "-"} | nextFollowUp=${stabilizationStatusReceipt.operatorHandoffFiles?.nextFollowUp || "-"} | postLaunchIndex=${stabilizationStatusReceipt.operatorHandoffFiles?.postLaunchIndex || "-"}`);
    lines.push("");
  }
  const operationalExceptionEntry = readiness.operationalExceptionEntry
    || readiness.traceability?.operationalExceptionEntry
    || null;
  if (operationalExceptionEntry) {
    lines.push("Operational Exception Entry:");
    lines.push(`- Status: ${operationalExceptionEntry.status || "-"} | severity=${operationalExceptionEntry.severity || "-"} | stage=${operationalExceptionEntry.stage || "-"}`);
    lines.push(`- Next: action=${operationalExceptionEntry.actionKey || "-"} | operation=${operationalExceptionEntry.operation || "-"} | download=${operationalExceptionEntry.downloadKey || "-"}`);
    lines.push(`- Workspace: ${operationalExceptionEntry.workspaceAction?.label || "-"} | href=${operationalExceptionEntry.workspaceAction?.href || "-"}`);
    lines.push(`- Download: ${operationalExceptionEntry.download?.fileName || "-"} | format=${operationalExceptionEntry.download?.format || "-"} | href=${operationalExceptionEntry.download?.href || "-"}`);
    lines.push(`- Signals: watch=${operationalExceptionEntry.launchDayWatchStatus || "-"} | watchRecordDraft=${operationalExceptionEntry.watchRecordDraftStatus || "-"} | stabilization=${operationalExceptionEntry.stabilizationStatus || "-"} | audit=${operationalExceptionEntry.confirmationAuditLogId || operationalExceptionEntry.latestReceiptAuditLogId || "-"}`);
    if (Array.isArray(operationalExceptionEntry.reasons) && operationalExceptionEntry.reasons.length) {
      lines.push("- Reasons:");
      for (const item of operationalExceptionEntry.reasons) {
        lines.push(`  - ${item.key || "-"} | status=${item.status || "-"} | count=${item.count ?? "-"} | ${item.summary || "-"}`);
      }
    }
    lines.push("");
  }
  const operationalExceptionCloseout = readiness.operationalExceptionCloseout
    || readiness.traceability?.operationalExceptionCloseout
    || null;
  if (operationalExceptionCloseout) {
    lines.push("Operational Exception Closeout:");
    lines.push(`- Status: ${operationalExceptionCloseout.status || "-"} | canClose=${operationalExceptionCloseout.canClose === true} | reviewRequired=${operationalExceptionCloseout.reviewRequired === true}`);
    lines.push(`- Next: action=${operationalExceptionCloseout.nextActionKey || "-"} | operation=${operationalExceptionCloseout.nextOperation || "-"} | download=${operationalExceptionCloseout.downloadKey || "-"}`);
    lines.push(`- Source: exception=${operationalExceptionCloseout.sourceExceptionStatus || "-"} | severity=${operationalExceptionCloseout.severity || "-"} | reasons=${operationalExceptionCloseout.blockingReasonCount ?? 0}`);
    lines.push(`- Actions: resolutionAction=${operationalExceptionCloseout.resolutionAction?.operation || "-"} | closeoutReview=${operationalExceptionCloseout.closeoutReviewAction?.operation || "-"} | endpoint=${operationalExceptionCloseout.closeoutReviewAction?.endpoint || "-"}`);
    if (Array.isArray(operationalExceptionCloseout.closeoutCriteria) && operationalExceptionCloseout.closeoutCriteria.length) {
      lines.push("- Closeout Criteria:");
      for (const item of operationalExceptionCloseout.closeoutCriteria) {
        lines.push(`  - ${item.key || "-"} | status=${item.status || "-"} | ${item.summary || "-"}`);
      }
    }
    lines.push("");
  }
  const closeoutReadinessSummary = readiness.closeoutReadinessSummary
    || readiness.traceability?.closeoutReadinessSummary
    || null;
  if (closeoutReadinessSummary) {
    appendDeveloperOpsCloseoutReadinessSummaryLines(lines, closeoutReadinessSummary);
    lines.push("");
  }
  const steadyStateOperationalReview = readiness.steadyStateOperationalReview || null;
  if (steadyStateOperationalReview) {
    appendDeveloperOpsSteadyStateOperationalReviewLines(lines, steadyStateOperationalReview);
    lines.push("");
  }
  const steadyStateExceptionDigest = readiness.steadyStateExceptionDigest || null;
  if (steadyStateExceptionDigest) {
    appendDeveloperOpsSteadyStateExceptionDigestLines(lines, steadyStateExceptionDigest);
    lines.push("");
  }
  const steadyStateHandoffBrief = readiness.steadyStateHandoffBrief || null;
  if (steadyStateHandoffBrief) {
    appendDeveloperOpsSteadyStateHandoffBriefLines(lines, steadyStateHandoffBrief);
    lines.push("");
  }
  const steadyStateDutyBoard = readiness.steadyStateDutyBoard || null;
  if (steadyStateDutyBoard) {
    appendDeveloperOpsSteadyStateDutyBoardLines(lines, steadyStateDutyBoard);
    lines.push("");
  }
  const steadyStateDutyActionLinks = readiness.steadyStateDutyActionLinks || null;
  if (steadyStateDutyActionLinks) {
    appendDeveloperOpsSteadyStateDutyActionLinksLines(lines, steadyStateDutyActionLinks);
    lines.push("");
  }
  const latestSteadyStateDutyPlanReceipt = readiness.latestSteadyStateDutyPlanReceipt || null;
  if (latestSteadyStateDutyPlanReceipt) {
    lines.push("Steady-State Duty Plan Receipts:");
    lines.push(
      `- status=${latestSteadyStateDutyPlanReceipt.status || "-"}`
      + ` | audit=${latestSteadyStateDutyPlanReceipt.auditLogId || "-"}`
      + ` | action=${latestSteadyStateDutyPlanReceipt.action || "-"}`
      + ` | intent=${latestSteadyStateDutyPlanReceipt.intent || "-"}`
      + ` | plan=${latestSteadyStateDutyPlanReceipt.planKind || "-"}:${latestSteadyStateDutyPlanReceipt.planMode || "-"}`
      + ` | file=${latestSteadyStateDutyPlanReceipt.fileName || latestSteadyStateDutyPlanReceipt.format || "-"}`
    );
    if (latestSteadyStateDutyPlanReceipt.receiptVisibility) {
      lines.push(
        `- receiptVisibility=${latestSteadyStateDutyPlanReceipt.receiptVisibility.status || "-"}`
        + ` | visibleIn=${Array.isArray(latestSteadyStateDutyPlanReceipt.receiptVisibility.visibleIn) ? latestSteadyStateDutyPlanReceipt.receiptVisibility.visibleIn.length : 0}`
        + ` | recovery=${latestSteadyStateDutyPlanReceipt.receiptVisibility.failureRecovery?.method || "-"} ${latestSteadyStateDutyPlanReceipt.receiptVisibility.failureRecovery?.route || "-"}`
      );
    }
    lines.push("");
  }
  const launchOperationsEvidenceChain = readiness.launchOperationsEvidenceChain || null;
  if (launchOperationsEvidenceChain) {
    appendDeveloperOpsLaunchOperationsEvidenceChainLines(lines, launchOperationsEvidenceChain);
    lines.push("");
  }
  const launchOperationsHandoffSummary = readiness.launchOperationsHandoffSummary || null;
  if (launchOperationsHandoffSummary) {
    appendDeveloperOpsLaunchOperationsHandoffSummaryLines(lines, launchOperationsHandoffSummary);
    lines.push("");
  }
  const launchOperationsDailyBrief = readiness.launchOperationsDailyBrief || null;
  if (launchOperationsDailyBrief) {
    appendDeveloperOpsLaunchOperationsDailyBriefLines(lines, launchOperationsDailyBrief);
    lines.push("");
  }
  const launchOperationsShiftActionPlan = readiness.launchOperationsShiftActionPlan || null;
  if (launchOperationsShiftActionPlan) {
    appendDeveloperOpsLaunchOperationsShiftActionPlanLines(lines, launchOperationsShiftActionPlan);
    lines.push("");
  }
  const launchOperationsOverviewStatus = readiness.launchOperationsOverviewStatus || null;
  if (launchOperationsOverviewStatus) {
    appendDeveloperOpsLaunchOperationsOverviewStatusLines(lines, launchOperationsOverviewStatus);
    lines.push("");
  }
  const formatGateDownloadText = (item = {}) => {
    const recommendedDownload = item.recommendedDownload && typeof item.recommendedDownload === "object"
      ? item.recommendedDownload
      : null;
    return [
      `download=${item.downloadKey || recommendedDownload?.key || "-"}`,
      item.downloadFileName || recommendedDownload?.fileName ? `file=${item.downloadFileName || recommendedDownload?.fileName}` : "",
      item.downloadFormat || recommendedDownload?.format ? `format=${item.downloadFormat || recommendedDownload?.format}` : "",
      item.downloadHref || recommendedDownload?.href ? `href=${item.downloadHref || recommendedDownload?.href}` : ""
    ].filter(Boolean).join(" | ");
  };
  lines.push("Blockers:");
  const blockers = Array.isArray(gate.blockers) ? gate.blockers : [];
  if (blockers.length) {
    for (const item of blockers) {
      lines.push(`- [${item.stage || "-"}] ${item.title || "-"} | priority=${item.priority || "-"} | operation=${item.operation || "-"} | action=${item.actionKey || "-"} | ${formatGateDownloadText(item)}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Required Actions:");
  const requiredActions = Array.isArray(gate.requiredActions) ? gate.requiredActions : [];
  if (requiredActions.length) {
    for (const item of requiredActions) {
      lines.push(`- ${item.label || item.key || "-"} | stage=${item.stage || "-"} | operation=${item.operation || "-"} | action=${item.actionKey || "-"} | ${formatGateDownloadText(item)}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Warnings:");
  const warnings = Array.isArray(gate.warnings) ? gate.warnings : [];
  if (warnings.length) {
    for (const item of warnings) {
      lines.push(`- [${item.stage || "-"}] ${item.title || "-"} | priority=${item.priority || "-"} | operation=${item.operation || "-"} | action=${item.actionKey || "-"} | ${formatGateDownloadText(item)}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Follow-up Queue:");
  const followUpQueue = Array.isArray(readiness.followUpQueue) ? readiness.followUpQueue : [];
  if (followUpQueue.length) {
    for (const item of followUpQueue) {
      lines.push(`- [${item.stage || "-"}] ${item.title || "-"} | priority=${item.priority || "-"} | operation=${item.operationToRecord || item.operation || "-"} | action=${item.actionKey || "-"} | download=${item.downloadKey || "-"} | href=${item.downloadHref || item.recommendedDownload?.href || "-"} | handoff=${item.handoffFileName || "-"}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Recommended Downloads:");
  const recommendedDownloads = Array.isArray(readiness.recommendedDownloads) ? readiness.recommendedDownloads : [];
  if (recommendedDownloads.length) {
    for (const item of recommendedDownloads) {
      lines.push(`- ${item.label || item.key || "-"} | file=${item.fileName || "-"} | format=${item.format || "-"} | href=${item.href || "-"}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Next Steps:");
  const nextSteps = Array.isArray(readiness.nextSteps) ? readiness.nextSteps : [];
  if (nextSteps.length) {
    for (const item of nextSteps) {
      lines.push(`- ${item}`);
    }
  } else {
    lines.push("- Continue monitoring the scoped Developer Ops snapshot.");
  }
  return lines.join("\n");
}

function buildDeveloperOpsSteadyStateOperationalReviewText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const review = readiness.steadyStateOperationalReview || buildDeveloperOpsSteadyStateOperationalReviewPayload({
    scope,
    latestReceipt: readiness.latestReceipt || payload.overview?.latestLaunchReceipts?.[0] || null,
    closeoutReadinessSummary: readiness.closeoutReadinessSummary || null,
    launchDayWatchReceipt: readiness.launchDayWatchReceipt || null,
    stabilizationStatusReceipt: readiness.stabilizationStatusReceipt || null,
    firstWaveConfirmationChain: readiness.firstWaveConfirmationChain || null,
    followUpQueue: readiness.followUpQueue || [],
    stabilizationHandoff: readiness.stabilizationHandoff || null
  });
  const lines = [
    "RockSolid Developer Ops Steady-State Operational Review",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Code: ${review?.projectCode || scope.productCode || "-"}`,
    `Channel: ${review?.channel || scope.channel || "stable"}`,
    `Status: ${String(review?.status || readiness.closeoutReadinessSummary?.status || readiness.status || "unknown").toUpperCase()}`,
    `Monitoring Ready: ${review?.monitoringReady === true ? "yes" : "no"}`,
    `Headline: ${review?.headline || "-"}`,
    `Summary: ${review?.summary || "-"}`,
    ""
  ];
  if (!review) {
    lines.push("No steady-state operational review is available for this scoped Ops snapshot yet.");
    return lines.join("\n");
  }
  appendDeveloperOpsSteadyStateOperationalReviewLines(lines, review, {
    title: "Review Signals:"
  });
  lines.push("");
  lines.push("Operator Order:");
  lines.push("- Download this file when handing the first stable operating lane to the next operator.");
  lines.push("- Keep stabilization-handoff.txt and initial-launch-ops-readiness.txt attached beside this recap.");
  lines.push("- Re-open the scoped Developer Ops snapshot before widening rollout or changing operator ownership.");
  return lines.join("\n");
}

function buildDeveloperOpsSteadyStateExceptionDigestText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const digest = readiness.steadyStateExceptionDigest || buildDeveloperOpsSteadyStateExceptionDigestPayload({
    scope,
    overview: payload.overview || {},
    latestReceipt: readiness.latestReceipt || payload.overview?.latestLaunchReceipts?.[0] || null,
    closeoutReadinessSummary: readiness.closeoutReadinessSummary || null,
    steadyStateOperationalReview: readiness.steadyStateOperationalReview || null
  });
  const lines = [
    "RockSolid Developer Ops Steady-State Exception Digest",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Code: ${digest?.projectCode || scope.productCode || "-"}`,
    `Channel: ${digest?.channel || scope.channel || "stable"}`,
    `Status: ${String(digest?.status || "unknown").toUpperCase()}`,
    `Monitoring Ready: ${digest?.monitoringReady === true ? "yes" : "no"}`,
    `Queue Status: ${String(digest?.queueStatus || "unknown").toUpperCase()}`,
    `Summary: ${digest?.summary || "-"}`,
    ""
  ];
  if (!digest) {
    lines.push("No steady-state exception digest is available for this scoped Ops snapshot yet.");
    return lines.join("\n");
  }
  appendDeveloperOpsSteadyStateExceptionDigestLines(lines, digest, {
    title: "Exception Queue:"
  });
  lines.push("");
  lines.push("Top Audit Signals:");
  if (Array.isArray(digest.auditSignals) && digest.auditSignals.length) {
    for (const item of digest.auditSignals) {
      lines.push(`- ${item.eventType || "-"} x${item.count ?? 0}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Focus Users:");
  if (Array.isArray(digest.focusUsers) && digest.focusUsers.length) {
    for (const item of digest.focusUsers) {
      lines.push(`- ${item.username || "-"} x${item.count ?? 0}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Focus Devices:");
  if (Array.isArray(digest.focusDevices) && digest.focusDevices.length) {
    for (const item of digest.focusDevices) {
      lines.push(`- ${item.fingerprint || "-"} x${item.count ?? 0}`);
    }
  } else {
    lines.push("- none");
  }
  return lines.join("\n");
}

function buildDeveloperOpsSteadyStateHandoffBriefText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const brief = readiness.steadyStateHandoffBrief || buildDeveloperOpsSteadyStateHandoffBriefPayload({
    scope,
    latestReceipt: readiness.latestReceipt || payload.overview?.latestLaunchReceipts?.[0] || null,
    closeoutReadinessSummary: readiness.closeoutReadinessSummary || null,
    steadyStateOperationalReview: readiness.steadyStateOperationalReview || null,
    steadyStateExceptionDigest: readiness.steadyStateExceptionDigest || null,
    stabilizationHandoff: readiness.stabilizationHandoff || null
  });
  const lines = [
    "RockSolid Developer Ops Steady-State Handoff Brief",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Code: ${brief?.projectCode || scope.productCode || "-"}`,
    `Channel: ${brief?.channel || scope.channel || "stable"}`,
    `Status: ${String(brief?.status || "unknown").toUpperCase()}`,
    `Handoff Ready: ${brief?.handoffReady === true ? "yes" : "no"}`,
    `Summary: ${brief?.summary || "-"}`,
    ""
  ];
  if (!brief) {
    lines.push("No steady-state handoff brief is available for this scoped Ops snapshot yet.");
    return lines.join("\n");
  }
  appendDeveloperOpsSteadyStateHandoffBriefLines(lines, brief, {
    title: "Handoff Signals:"
  });
  lines.push("");
  lines.push("Download Set:");
  const downloadSet = Array.isArray(brief.downloadSet) ? brief.downloadSet : [];
  if (downloadSet.length) {
    for (const item of downloadSet) {
      lines.push(`- ${item.role || item.key || "-"} | file=${item.fileName || "-"} | format=${item.format || "-"} | href=${item.href || "-"}`);
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Operator Handoff:");
  if (Array.isArray(brief.operatorActions) && brief.operatorActions.length) {
    for (const item of brief.operatorActions) {
      lines.push(`- ${item}`);
    }
  } else {
    lines.push("- Open Developer Ops and attach the current review and exception digest.");
  }
  return lines.join("\n");
}

