function buildDeveloperOpsSteadyStateDutyActionLinksText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const actionLinks = readiness.steadyStateDutyActionLinks || buildDeveloperOpsSteadyStateDutyActionLinksPayload({
    scope,
    steadyStateDutyBoard: readiness.steadyStateDutyBoard || null
  });
  const lines = [
    "RockSolid Developer Ops Steady-State Duty Action Links",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Code: ${actionLinks?.projectCode || scope.productCode || "-"}`,
    `Channel: ${actionLinks?.channel || scope.channel || "stable"}`,
    `Status: ${String(actionLinks?.status || "unknown").toUpperCase()}`,
    `Ready For Duty: ${actionLinks?.readyForDuty === true ? "yes" : "no"}`,
    `Summary: ${actionLinks?.summary || "-"}`,
    ""
  ];
  if (!actionLinks) {
    lines.push("No steady-state duty action links are available for this scoped Ops snapshot yet.");
    return lines.join("\n");
  }
  appendDeveloperOpsSteadyStateDutyActionLinksLines(lines, actionLinks, {
    title: "Action Link Summary:"
  });
  const appendSection = (title, items = []) => {
    lines.push("");
    lines.push(`${title}:`);
    if (Array.isArray(items) && items.length) {
      for (const item of items) {
        lines.push(`- ${item.label || item.key || "-"} | priority=${item.priority || "-"} | source=${item.source || "-"} | href=${item.href || "-"}${item.fileName ? ` | file=${item.fileName}` : ""}${item.format ? ` | format=${item.format}` : ""}`);
      }
    } else {
      lines.push("- none");
    }
  };
  const appendIntentSection = (title, items = []) => {
    lines.push("");
    lines.push(`${title}:`);
    if (Array.isArray(items) && items.length) {
      for (const item of items) {
        lines.push(
          `- intent=${item.intent || "-"}`
          + ` | label=${item.label || item.key || "-"}`
          + ` | target=${item.targetType || "-"}`
          + ` | method=${item.method || "-"}`
          + ` | confirm=${item.requiresConfirmation === true ? "yes" : "no"}`
          + ` | plan=${item.executionPlan?.kind || "-"}:${item.executionPlan?.mode || "-"}`
          + ` | href=${item.href || "-"}`
          + (item.fileName ? ` | file=${item.fileName}` : "")
          + (item.format ? ` | format=${item.format}` : "")
        );
      }
    } else {
      lines.push("- none");
    }
  };
  const appendExecutionPlanSection = (title, items = []) => {
    lines.push("");
    lines.push(`${title}:`);
    const plans = Array.isArray(items)
      ? items.map((item) => item.executionPlan).filter(Boolean)
      : [];
    if (plans.length) {
      for (const plan of plans) {
        lines.push(
          `- kind=${plan.kind || "-"}`
          + ` | mode=${plan.mode || "-"}`
          + ` | status=${plan.status || "-"}`
          + ` | method=${plan.method || "-"}`
          + ` | href=${plan.href || "-"}`
          + (plan.fileName ? ` | file=${plan.fileName}` : "")
          + (plan.format ? ` | format=${plan.format}` : "")
          + (plan.confirmationLabel ? ` | confirm=${plan.confirmationLabel}` : "")
        );
      }
    } else {
      lines.push("- none");
    }
  };
  appendSection("Workspace Links", actionLinks.workspaceLinks);
  appendSection("Download Links", actionLinks.downloadLinks);
  appendSection("Control Links", actionLinks.controlLinks);
  appendIntentSection("Control Intents", actionLinks.controlIntents);
  appendExecutionPlanSection("Execution Plans", actionLinks.controlIntents);
  return lines.join("\n");
}

function buildDeveloperOpsStabilizationHandoffText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const handoff = readiness.stabilizationHandoff || null;
  const launchReceiptAuditBackfill = Number(
    summary.launchReceiptAuditBackfill
    ?? payload.auditLogs?.filters?.launchReceiptBackfill
    ?? 0
  );
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const lines = [
    "RockSolid Developer Ops Stabilization Handoff",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    `Status: ${String(handoff?.status || readiness.status || "unknown").toUpperCase()}`,
    `Decision: ${String(handoff?.decision || readiness.goNoGo?.decision || readiness.gate?.decision || "unknown").toUpperCase()}`,
    ""
  ];

  if (!handoff) {
    lines.push("No stabilization handoff evidence is available for this scoped Ops snapshot yet.");
    lines.push("Next Action: -");
    return lines.join("\n");
  }

  const latestReceipt = handoff.latestLaunchReceipt || {};
  const latestOperator = handoff.latestOperatorActionReceipt || {};
  const nextAction = handoff.nextAction || {};
  const files = handoff.files || {};
  lines.push(`Version: ${handoff.version || "-"}`);
  lines.push(`Generated For: ${handoff.generatedFor || "-"}`);
  lines.push(`Project Code: ${handoff.projectCode || scope.productCode || "-"}`);
  lines.push(`Channel: ${handoff.channel || "-"}`);
  lines.push(`Latest Receipt: ${latestReceipt.operation || "-"} | handoff=${latestReceipt.handoffFileName || "-"} | gate=${latestReceipt.mainlineGateStatus || "-"}`);
  lines.push(`Post-Launch: status=${latestReceipt.postLaunchLifecycleStatus || "-"} | next=${latestReceipt.postLaunchLifecycleNextOperation || "-"}`);
  lines.push(`Latest Operator: ${latestOperator.operation || "-"} | audit=${latestOperator.auditLogId || "-"} | next=${latestOperator.nextOperation || "-"}`);
  lines.push(`Next Action: ${nextAction.operation || "-"} | stage=${nextAction.stage || "-"} | action=${nextAction.actionKey || "-"} | priority=${nextAction.priority || "-"}`);
  lines.push(`Download: ${nextAction.downloadFileName || nextAction.downloadKey || "-"} | key=${nextAction.downloadKey || "-"} | href=${nextAction.downloadHref || "-"}`);
  lines.push(`Workspace Href: ${nextAction.workspaceHref || "-"}`);
  lines.push(`Files: readiness=${files.readiness || "-"} | handoffIndex=${files.handoffIndex || "-"} | nextFollowUp=${files.nextFollowUp || "-"} | postLaunchIndex=${files.postLaunchIndex || "-"}`);
  const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(handoff.launchOpsOverviewContext);
  if (launchOpsOverviewContext) {
    lines.push("");
    lines.push("Launch Ops Overview Context:");
    lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
    lines.push(`- download: ${formatLaunchHandoffDownloadText(buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext), { fileSeparator: " | " })}`);
  }
  const confirmation = handoff.confirmation || null;
  if (confirmation) {
    lines.push(`Confirmation: ${confirmation.status || "-"} | audit=${confirmation.auditLogId || "-"} | decision=${confirmation.decision || "-"} | by=${confirmation.confirmedBy?.username || "-"} | file=${confirmation.handoffFileName || "-"}`);
  }
  lines.push("");
  lines.push("Checklist:");
  if (Array.isArray(handoff.checklist) && handoff.checklist.length) {
    for (const item of handoff.checklist) {
      lines.push(`- ${item}`);
    }
  } else {
    lines.push("- Re-open Developer Ops and Launch Mainline before handing off stabilization duty.");
  }
  lines.push("");
  lines.push("Operator Order:");
  lines.push("- Open Launch Mainline with the workspace href above when the next stabilization action must be recorded.");
  lines.push("- Download this file with the Ops zip when handing stabilization duty to another operator.");
  lines.push("- Keep initial-launch-ops-readiness.txt and launch-receipt-next-follow-up.txt attached for traceability.");
  return lines.join("\n");
}

function buildDeveloperOpsLaunchMainlineHandoffRoutesText(payload = {}) {
  const scope = payload.scope || {};
  const readiness = payload.summary?.initialLaunchOpsReadiness || {};
  const traceability = readiness.traceability || {};
  const latestLaunchReceipt = traceability.latestLaunchReceipt || {};
  const launchMainlineFiles = traceability.launchMainlineFiles || {};
  const overviewStatusScope = {
    ...scope,
    productCode: scope.productCode || latestLaunchReceipt.productCode || "",
    channel: scope.channel || latestLaunchReceipt.channel || "stable"
  };
  const launchOpsOverviewContext = buildScopedLaunchOpsOverviewContext(
    overviewStatusScope,
    traceability.stabilizationHandoffConfirmation?.launchOpsOverviewContext
    || readiness.stabilizationHandoff?.confirmation?.launchOpsOverviewContext
    || readiness.launchOperationsOverviewStatus?.launchOpsOverviewContext
  );
  const launchOpsOverviewDownload = buildScopedLaunchOpsOverviewContextDownload(
    overviewStatusScope,
    launchOpsOverviewContext
  );
  const routeParams = compactRouteParams({
    productCode: scope.productCode || latestLaunchReceipt.productCode || "",
    channel: scope.channel || latestLaunchReceipt.channel || "stable",
    username: scope.username || "",
    search: scope.search || "",
    eventType: scope.eventType || "",
    actorType: scope.actorType || "",
    entityType: scope.entityType || "",
    limit: scope.auditLimit || "",
    reviewMode: "matched"
  });
  const downloads = [
    [
      "launch-mainline-handoff-download-routes",
      createLaunchMainlineDownloadShortcut(
        "Launch Mainline handoff download routes",
        launchMainlineFiles.handoffDownloadRoutes || "handoff-download-routes.txt",
        "handoff-download-routes",
        routeParams
      )
    ],
    [
      "launch-mainline-post-launch-handoff-index",
      createLaunchMainlineDownloadShortcut(
        "Launch Mainline post-launch handoff index",
        "developer-launch-mainline-post-launch-handoff-index.txt",
        "post-launch-handoff-index",
        routeParams
      )
    ],
    [
      "launch-mainline-summary",
      createLaunchMainlineDownloadShortcut(
        "Launch Mainline summary",
        "developer-launch-mainline-summary.txt",
        "summary",
        routeParams
      )
    ],
    [
      "launch-mainline-checksums",
      createLaunchMainlineDownloadShortcut(
        "Launch Mainline checksums",
        "developer-launch-mainline-sha256.txt",
        "checksums",
        routeParams
      )
    ],
    [
      "launch-mainline-zip",
      createLaunchMainlineDownloadShortcut(
        "Launch Mainline zip",
        "developer-launch-mainline.zip",
        "zip",
        routeParams
      )
    ]
  ];
  if (launchOpsOverviewDownload) {
    downloads.push([
      "launch-ops-overview-status",
      launchOpsOverviewDownload
    ]);
  }
  const lines = [
    "RockSolid Developer Ops Launch Mainline Handoff Routes",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Channel: ${scope.channel || latestLaunchReceipt.channel || "stable"}`
  ];
  appendLaunchReceiptAuditBackfillStatusText(lines, payload);
  lines.push(
    "",
    "Launch Mainline Direct Downloads:"
  );
  for (const [key, download] of downloads) {
    lines.push(`- ${key}: ${formatLaunchHandoffDownloadText(download, { fileSeparator: " | " })}`);
  }
  if (launchOpsOverviewContext) {
    lines.push("");
    lines.push("Launch Ops Overview Context:");
    lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
    lines.push(`- download=${formatLaunchHandoffDownloadText(launchOpsOverviewDownload, { fileSeparator: " | " })}`);
  }
  lines.push("");
  lines.push("Operator Order:");
  lines.push("- Open this file from the Developer Ops export when handing launch duty to a reviewer who does not have the Launch Mainline zip open.");
  lines.push("- Prefer the handoff-download-routes link when the reviewer needs the complete Launch Mainline route map.");
  lines.push("- Keep this file beside handoff-index.txt so Ops and Launch Mainline reviewers share the same download hrefs.");
  return lines.join("\n");
}

function buildDeveloperOpsLaunchOperationsHandoffSummaryText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const handoffSummary = readiness.launchOperationsHandoffSummary || buildDeveloperOpsLaunchOperationsHandoffSummaryPayload({
    scope,
    launchOperationsEvidenceChain: readiness.launchOperationsEvidenceChain || null,
    steadyStateOperationalReview: readiness.steadyStateOperationalReview || null,
    steadyStateExceptionDigest: readiness.steadyStateExceptionDigest || null,
    steadyStateHandoffBrief: readiness.steadyStateHandoffBrief || null,
    steadyStateDutyBoard: readiness.steadyStateDutyBoard || null,
    steadyStateDutyActionLinks: readiness.steadyStateDutyActionLinks || null,
    latestSteadyStateDutyPlanReceipt: readiness.latestSteadyStateDutyPlanReceipt || null
  });
  const chain = readiness.launchOperationsEvidenceChain || null;
  const checklist = Array.isArray(handoffSummary?.handoffChecklist)
    ? handoffSummary.handoffChecklist
    : [];
  const supportingDownloads = Array.isArray(handoffSummary?.supportingDownloads)
    ? handoffSummary.supportingDownloads
    : [];
  const launchOpsOverviewContext = normalizeLaunchOpsOverviewContext(handoffSummary?.launchOpsOverviewContext);
  const lines = [
    "RockSolid Developer Ops Launch Operations Handoff Summary",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Code: ${handoffSummary?.productCode || scope.productCode || "-"}`,
    `Channel: ${handoffSummary?.channel || scope.channel || "stable"}`,
    `Status: ${String(handoffSummary?.status || "unknown").toUpperCase()}`,
    `Operator Summary: ${handoffSummary?.operatorSummary || "-"}`,
    `Watch Record Draft: watchRecordDraft=${handoffSummary?.watchRecordDraftStatus || "-"} | records=${handoffSummary?.watchRecordDraftRecordCount ?? "-"}`,
    `Production Signoff: productionSignoffPacket=${handoffSummary?.productionSignoffPacket || "-"} | launchDayWatchEntry=${handoffSummary?.launchDayWatchEntry || "-"}`,
    ""
  ];
  if (launchOpsOverviewContext) {
    lines.push("Launch Operations Handoff Summary:");
    lines.push(
      `- productionSignoffPacket=${handoffSummary?.productionSignoffPacket || "-"}`
      + ` | launchDayWatchEntry=${handoffSummary?.launchDayWatchEntry || "-"}`
    );
    lines.push(`- ${formatLaunchWorkflowActionContextText(launchOpsOverviewContext)}`);
    lines.push(
      `- launchOpsOverviewDownload=${formatLaunchHandoffDownloadText(
        buildScopedLaunchOpsOverviewContextDownload(scope, launchOpsOverviewContext),
        { fileSeparator: " | " }
      )}`
    );
    lines.push("");
  }
  if (chain) {
    lines.push("Evidence Chain:");
    lines.push(
      `- status=${chain.status || "-"}`
      + ` | complete=${chain.complete === true}`
      + ` | completed=${chain.completedStageCount ?? 0}/${chain.requiredStageCount ?? 0}`
      + ` | latest=${chain.latestStage?.key || "-"}`
    );
    for (const item of Array.isArray(chain.stages) ? chain.stages : []) {
      lines.push(
        `- ${item.key || "-"}`
        + ` | status=${item.status || "-"}`
        + ` | audit=${item.auditLogId || "-"}`
        + ` | action=${item.action || item.operation || "-"}`
        + ` | file=${item.fileName || item.format || "-"}`
      );
    }
    lines.push("");
  }
  lines.push("Next Review:");
  lines.push(
    `- key=${handoffSummary?.nextReviewAction?.key || "-"}`
    + ` | stage=${handoffSummary?.nextReviewAction?.stageKey || "-"}`
    + ` | status=${handoffSummary?.nextReviewAction?.status || "-"}`
    + ` | summary=${handoffSummary?.nextReviewAction?.summary || "-"}`
  );
  lines.push("");
  lines.push("Handoff Download:");
  lines.push(
    `- file=${handoffSummary?.handoffDownload?.fileName || "-"}`
    + ` | format=${handoffSummary?.handoffDownload?.format || "-"}`
    + ` | href=${handoffSummary?.handoffDownload?.href || "-"}`
  );
  lines.push("");
  appendDeveloperOpsReceiptVisibilitySummaryLines(lines, handoffSummary?.receiptVisibilitySummary);
  lines.push("");
  lines.push("Handoff Checklist:");
  if (checklist.length) {
    for (const item of checklist) {
      lines.push(
        `- ${item.key || "-"}`
        + ` | status=${item.status || "-"}`
        + ` | ready=${item.ready === true ? "yes" : "no"}`
        + ` | audit=${item.auditLogId || "-"}`
        + ` | action=${item.action || "-"}`
        + ` | file=${item.fileName || "-"}`
      );
    }
  } else {
    lines.push("- none");
  }
  lines.push("");
  lines.push("Supporting Downloads:");
  if (supportingDownloads.length) {
    for (const item of supportingDownloads) {
      lines.push(
        `- ${item.label || item.key || "-"}`
        + ` | file=${item.fileName || "-"}`
        + ` | format=${item.format || "-"}`
        + ` | href=${item.href || "-"}`
      );
    }
  } else {
    lines.push("- none");
  }
  return lines.join("\n");
}

