function buildDeveloperOpsHandoffIndexText(payload = {}) {
  const scope = payload.scope || {};
  const summary = payload.summary || {};
  const readiness = summary.initialLaunchOpsReadiness || buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview: payload.overview || {},
    launchReceiptFollowUps: payload.overview?.launchReceiptFollowUps || [],
    launchReceiptFollowUpPriorities: summary.launchReceiptFollowUpPriorities || {},
    launchReceiptNextFollowUp: summary.launchReceiptNextFollowUp || null,
    mainlineHandoff: payload.mainlineHandoff || null
  });
  const gate = readiness.gate || {};
  const followUpQueue = Array.isArray(readiness.followUpQueue) ? readiness.followUpQueue : [];
  const recommendedDownloads = Array.isArray(readiness.recommendedDownloads) ? readiness.recommendedDownloads : [];
  const launchReceiptAuditBackfill = Number(
    summary.launchReceiptAuditBackfill
    ?? payload.auditLogs?.filters?.launchReceiptBackfill
    ?? 0
  );
  const launchReceiptAuditBackfillStatus = summary.launchReceiptAuditBackfillStatus
    || buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const includedFiles = [
    payload.fileName || "developer-ops.json",
    payload.summaryFileName || "developer-ops-summary.txt",
    "handoff-index.txt",
    "launch-receipt-next-follow-up.txt",
    "launch-receipt-backfill-status.txt",
    "first-wave-audit-backfill-status.txt",
    "first-wave-runtime-evidence.txt",
    "initial-launch-ops-readiness.txt",
    "staging-launch-duty-archive.txt",
    "stabilization-handoff.txt",
    "steady-state-operational-review.txt",
    "steady-state-exception-digest.txt",
    "steady-state-handoff-brief.txt",
    "steady-state-duty-board.txt",
    "steady-state-duty-action-links.txt",
    "launch-operations-handoff-summary.txt",
    "launch-operations-daily-brief.txt",
    "launch-operations-shift-action-plan.txt",
    "launch-operations-overview-status.txt",
    "launch-mainline-handoff-routes.txt",
    "csv/projects.csv",
    "csv/accounts.csv",
    "csv/entitlements.csv",
    "csv/sessions.csv",
    "csv/device-bindings.csv",
    "csv/device-blocks.csv",
    "csv/audit-logs.csv",
    "csv/launch-receipt-follow-ups.csv"
  ];
  const lines = [
    "RockSolid Developer Ops Launch Handoff Index",
    `Generated At: ${payload.generatedAt || ""}`,
    `Project Filter: ${scope.productCode || "-"}`,
    `Audit Event Filter: ${scope.eventType || "-"}`,
    `Launch Receipt Audit Backfill: ${launchReceiptAuditBackfill}`,
    `Launch Receipt Audit Backfill Status: ${launchReceiptAuditBackfillStatus.used ? "USED" : "NOT_USED"}`,
    `Launch Receipt Audit Backfill Source: ${launchReceiptAuditBackfillStatus.source || "-"}`,
    `Launch Receipt Audit Backfill Operator Hint: ${launchReceiptAuditBackfillStatus.operatorHint || "-"}`,
    `Initial Launch Ops Readiness: ${String(readiness.status || "unknown").toUpperCase()}`,
    `Gate Decision: ${String(gate.decision || "unknown").toUpperCase()}`,
    `Can Enter Initial Launch: ${gate.canEnterInitialLaunch === true ? "yes" : "no"}`,
    `Next Follow-up: ${formatLaunchReceiptNextFollowUp(readiness.nextFollowUp || summary.launchReceiptNextFollowUp || null)}`,
    `Primary Workspace: ${readiness.primaryWorkspaceAction?.label || "-"} | href=${readiness.primaryWorkspaceAction?.href || "-"}`,
    `Primary Download: ${readiness.primaryDownload?.fileName || "-"} | format=${readiness.primaryDownload?.format || "-"} | href=${readiness.primaryDownload?.href || "-"}`,
    `Steady-State Review: ${String(readiness.steadyStateOperationalReview?.status || "-").toUpperCase()} | ready=${readiness.steadyStateOperationalReview?.monitoringReady === true ? "yes" : "no"} | file=${readiness.steadyStateOperationalReview?.reviewDownload?.fileName || "-"}`,
    `Steady-State Exception Digest: ${String(readiness.steadyStateExceptionDigest?.status || "-").toUpperCase()} | queue=${readiness.steadyStateExceptionDigest?.queueSummary?.total ?? 0} | file=${readiness.steadyStateExceptionDigest?.digestDownload?.fileName || "-"}`,
    `Steady-State Handoff Brief: ${String(readiness.steadyStateHandoffBrief?.status || "-").toUpperCase()} | ready=${readiness.steadyStateHandoffBrief?.handoffReady === true ? "yes" : "no"} | file=${readiness.steadyStateHandoffBrief?.handoffDownload?.fileName || "-"}`,
    `Steady-State Duty Board: ${String(readiness.steadyStateDutyBoard?.status || "-").toUpperCase()} | ready=${readiness.steadyStateDutyBoard?.readyForDuty === true ? "yes" : "no"} | file=${readiness.steadyStateDutyBoard?.boardDownload?.fileName || "-"}`,
    `Steady-State Duty Action Links: ${String(readiness.steadyStateDutyActionLinks?.status || "-").toUpperCase()} | actions=${readiness.steadyStateDutyActionLinks?.actionCount ?? 0} | file=${readiness.steadyStateDutyActionLinks?.actionLinksDownload?.fileName || "-"}`,
    `Launch Operations Handoff Summary: ${String(readiness.launchOperationsHandoffSummary?.status || "-").toUpperCase()} | evidence=${readiness.launchOperationsHandoffSummary?.evidenceChainStatus || "-"} | file=${readiness.launchOperationsHandoffSummary?.handoffDownload?.fileName || "-"}`,
    `Launch Operations Daily Brief: ${String(readiness.launchOperationsDailyBrief?.status || "-").toUpperCase()} | nextReview=${readiness.launchOperationsDailyBrief?.nextReviewAction?.key || "-"} | file=${readiness.launchOperationsDailyBrief?.briefDownload?.fileName || "-"}`,
    `Launch Operations Shift Action Plan: ${String(readiness.launchOperationsShiftActionPlan?.status || "-").toUpperCase()} | primary=${readiness.launchOperationsShiftActionPlan?.primaryAction?.key || "-"} | file=${readiness.launchOperationsShiftActionPlan?.actionPlanDownload?.fileName || "-"}`,
    `Launch Operations Overview Status: ${String(readiness.launchOperationsOverviewStatus?.status || "-").toUpperCase()} | receipt=${readiness.launchOperationsOverviewStatus?.receiptVisibilityStatus || "-"} | panels=${readiness.launchOperationsOverviewStatus?.readyPanelCount ?? 0}/${readiness.launchOperationsOverviewStatus?.panelCount ?? 0} | recovery=${readiness.launchOperationsOverviewStatus?.recoveryRoute || "-"} | file=${readiness.launchOperationsOverviewStatus?.overviewDownload?.fileName || "-"}`,
    `Launch Operations Overview Signoff: productionSignoffPacket=${readiness.launchOperationsOverviewStatus?.productionSignoffPacket || "-"} | launchDayWatchEntry=${readiness.launchOperationsOverviewStatus?.launchDayWatchEntry || "-"}`,
    ""
  ];

  if (readiness.launchDutyActionOrder) {
    appendDeveloperOpsLaunchDutyActionOrderLines(lines, readiness.launchDutyActionOrder);
    lines.push("");
  }

  lines.push("Follow-up Queue:");
  if (followUpQueue.length) {
    for (const item of followUpQueue) {
      lines.push(`- [${item.stage || "-"}] ${item.title || "-"} | priority=${item.priority || "-"} | operation=${item.operationToRecord || item.operation || "-"} | action=${item.actionKey || "-"} | download=${item.downloadKey || "-"} | href=${item.downloadHref || item.recommendedDownload?.href || "-"} | handoff=${item.handoffFileName || "-"}`);
    }
  } else {
    lines.push("- none");
  }

  const latestLaunchReceipts = Array.isArray(payload.overview?.latestLaunchReceipts)
    ? payload.overview.latestLaunchReceipts
    : [];
  const visibleReceipts = latestLaunchReceipts.filter((item) => item?.receiptVisibility);
  if (visibleReceipts.length) {
    lines.push("");
    lines.push("Latest Receipt Visibility:");
    for (const item of visibleReceipts) {
      lines.push(`- ${item.operationLabel || item.operation || "-"} | project=${item.productCode || "-"} | channel=${item.channel || "-"} | handoff=${item.handoffFileName || "-"}`);
      appendDeveloperOpsReceiptVisibilityText(lines, item);
    }
  }

  lines.push("");
  lines.push("Recommended Downloads:");
  if (recommendedDownloads.length) {
    for (const item of recommendedDownloads) {
      lines.push(`- ${item.label || item.key || "-"} | file=${item.fileName || "-"} | format=${item.format || "-"} | href=${item.href || "-"}`);
    }
  } else {
    lines.push("- none");
  }

  const launchDayWatchReceipt = readiness.launchDayWatchReceipt
    || readiness.traceability?.launchDayWatchReceipt
    || null;
  if (launchDayWatchReceipt) {
    lines.push("");
    lines.push("Launch-Day Watch Receipt:");
    lines.push(
      `- status=${launchDayWatchReceipt.status || "-"}`
      + ` | receiptRecorded=${launchDayWatchReceipt.receiptRecorded === true}`
      + ` | audit=${launchDayWatchReceipt.auditLogId || "-"}`
    );
    lines.push(
      `- latestReceipt=${launchDayWatchReceipt.operation || "-"}`
      + ` | handoff=${launchDayWatchReceipt.handoffFileName || "-"}`
      + ` | next=${launchDayWatchReceipt.nextOperation || "-"}`
      + ` | download=${launchDayWatchReceipt.primaryDownloadKey || "-"}`
    );
  }

  const stabilizationStatusReceipt = readiness.stabilizationStatusReceipt
    || readiness.traceability?.stabilizationStatusReceipt
    || null;
  if (stabilizationStatusReceipt) {
    lines.push("");
    lines.push("Stabilization Status Receipt:");
    lines.push(
      `- status=${stabilizationStatusReceipt.status || "-"}`
      + ` | confirmed=${stabilizationStatusReceipt.handoffConfirmed === true}`
      + ` | audit=${stabilizationStatusReceipt.confirmationAuditLogId || "-"}`
      + ` | followUps=${stabilizationStatusReceipt.followUpCount ?? 0}`
    );
    lines.push(
      `- latestReceipt=${stabilizationStatusReceipt.latestReceiptOperation || "-"}`
      + ` | watch=${stabilizationStatusReceipt.launchDayWatchStatus || "-"}`
      + ` | watchRecordDraft=${stabilizationStatusReceipt.watchRecordDraftStatus || "-"}`
      + ` | next=${stabilizationStatusReceipt.nextOperation || "-"}`
      + ` | steadyNext=${stabilizationStatusReceipt.steadyStateNextStep || "-"}`
    );
  }

  const operationalExceptionEntry = readiness.operationalExceptionEntry
    || readiness.traceability?.operationalExceptionEntry
    || null;
  if (operationalExceptionEntry) {
    lines.push("");
    lines.push("Operational Exception Entry:");
    lines.push(
      `- status=${operationalExceptionEntry.status || "-"}`
      + ` | severity=${operationalExceptionEntry.severity || "-"}`
      + ` | stage=${operationalExceptionEntry.stage || "-"}`
      + ` | operation=${operationalExceptionEntry.operation || "-"}`
    );
    lines.push(
      `- action=${operationalExceptionEntry.actionKey || "-"}`
      + ` | download=${operationalExceptionEntry.download?.fileName || operationalExceptionEntry.downloadKey || "-"}`
      + ` | workspace=${operationalExceptionEntry.workspaceAction?.label || "-"}@${operationalExceptionEntry.workspaceAction?.autofocus || "-"}`
    );
    lines.push(
      `- watch=${operationalExceptionEntry.launchDayWatchStatus || "-"}`
      + ` | watchRecordDraft=${operationalExceptionEntry.watchRecordDraftStatus || "-"}`
      + ` | stabilization=${operationalExceptionEntry.stabilizationStatus || "-"}`
      + ` | audit=${operationalExceptionEntry.confirmationAuditLogId || operationalExceptionEntry.latestReceiptAuditLogId || "-"}`
    );
  }

  const operationalExceptionCloseout = readiness.operationalExceptionCloseout
    || readiness.traceability?.operationalExceptionCloseout
    || null;
  if (operationalExceptionCloseout) {
    lines.push("");
    lines.push("Operational Exception Closeout:");
    lines.push(
      `- status=${operationalExceptionCloseout.status || "-"}`
      + ` | canClose=${operationalExceptionCloseout.canClose === true}`
      + ` | reviewRequired=${operationalExceptionCloseout.reviewRequired === true}`
      + ` | reasons=${operationalExceptionCloseout.blockingReasonCount ?? 0}`
    );
    lines.push(
      `- next=${operationalExceptionCloseout.nextOperation || "-"}`
      + ` | action=${operationalExceptionCloseout.nextActionKey || "-"}`
      + ` | download=${operationalExceptionCloseout.downloadKey || "-"}`
    );
    lines.push(
      `- actions: resolutionAction=${operationalExceptionCloseout.resolutionAction?.operation || "-"}`
      + ` | closeoutReview=${operationalExceptionCloseout.closeoutReviewAction?.operation || "-"}`
      + ` | endpoint=${operationalExceptionCloseout.closeoutReviewAction?.endpoint || "-"}`
    );
  }

  const closeoutReadinessSummary = readiness.closeoutReadinessSummary
    || readiness.traceability?.closeoutReadinessSummary
    || null;
  if (closeoutReadinessSummary) {
    lines.push("");
    appendDeveloperOpsCloseoutReadinessSummaryLines(lines, closeoutReadinessSummary);
  }

  const stagingArchive = readiness.stagingLaunchDutyArchive || null;
  if (stagingArchive) {
    lines.push("");
    appendDeveloperOpsStagingLaunchDutyArchiveLines(lines, stagingArchive);
  }

  const firstWaveHandoffConfirmation = readiness.firstWaveHandoffConfirmation || readiness.traceability?.firstWaveHandoffConfirmation || null;
  if (firstWaveHandoffConfirmation) {
    lines.push("");
    lines.push("First-Wave Handoff Confirmation:");
    lines.push(
      `- status=${firstWaveHandoffConfirmation.status || "-"}`
      + ` | audit=${firstWaveHandoffConfirmation.auditLogId || "-"}`
      + ` | decision=${firstWaveHandoffConfirmation.decision || "-"}`
      + ` | by=${firstWaveHandoffConfirmation.confirmedBy?.username || "-"}`
    );
    lines.push(
      `- file=${firstWaveHandoffConfirmation.handoffFileName || "-"}`
      + ` | inventory=${firstWaveHandoffConfirmation.sourceRecommendation?.inventoryStatus || "-"}`
      + ` | cards=${firstWaveHandoffConfirmation.sourceRecommendation?.firstCardStatus || "-"}`
      + ` | ops=${firstWaveHandoffConfirmation.sourceRecommendation?.firstRoundOpsStatus || "-"}`
    );
  }

  const firstWaveConfirmationChain = readiness.firstWaveConfirmationChain
    || readiness.traceability?.firstWaveConfirmationChain
    || firstWaveHandoffConfirmation?.firstWaveConfirmationChain
    || null;
  if (firstWaveConfirmationChain) {
    lines.push("");
    lines.push("First-Wave Confirmation Chain:");
    lines.push(
      `- status=${firstWaveConfirmationChain.status || "-"}`
      + ` | segments=${firstWaveConfirmationChain.confirmedSegmentCount ?? 0}/${firstWaveConfirmationChain.segmentCount ?? 0}`
      + ` | allConfirmed=${firstWaveConfirmationChain.allSegmentsConfirmed === true}`
      + ` | audit=${firstWaveConfirmationChain.auditLogId || "-"}`
    );
    lines.push(
      `- inventory=${firstWaveConfirmationChain.inventoryStatus || "-"}`
      + ` | firstCards=${firstWaveConfirmationChain.firstCardStatus || "-"}`
      + ` | firstRoundOps=${firstWaveConfirmationChain.firstRoundOpsStatus || "-"}`
      + ` | latestReceipt=${firstWaveConfirmationChain.latestLaunchReceiptOperation || "-"}`
    );
  }

  lines.push("");
  lines.push("Included Files:");
  for (const filePath of includedFiles) {
    lines.push(`- ${filePath}`);
  }

  lines.push("");
  lines.push("Operator Order:");
  lines.push("- Open this handoff index first when reviewing an exported Ops zip offline.");
  lines.push("- Use initial-launch-ops-readiness.txt for the current gate and launch duty decision.");
  lines.push("- Use launch-receipt-next-follow-up.txt for the next recorded Launch Mainline operation.");
  lines.push("- Use stabilization-handoff.txt when handing first-wave stabilization duty to the next operator.");
  lines.push("- Use steady-state-operational-review.txt for the first-round operations recap once closeout and stabilization reviews are both recorded.");
  lines.push("- Use steady-state-exception-digest.txt for the current exception queue, focus users, focus devices, and next operator controls.");
  lines.push("- Use steady-state-handoff-brief.txt as the single operator-facing handoff cover sheet.");
  lines.push("- Use steady-state-duty-board.txt as the active duty board with quick actions and handoff assets.");
  lines.push("- Use steady-state-duty-action-links.txt to jump from duty board actions to workspace, control, and download links.");
  lines.push("- Use launch-operations-handoff-summary.txt as the latest launch operations evidence summary for shift handoff.");
  lines.push("- Use launch-operations-daily-brief.txt as the shift-start daily brief for launch-day watch and stable-lane handoff.");
  lines.push("- Use launch-operations-shift-action-plan.txt as the ordered operator checklist for the active launch watch shift.");
  lines.push("- Use launch-operations-overview-status.txt as the one-screen launch operations status before and during cutover.");
  lines.push("- Use launch-mainline-handoff-routes.txt when the next reviewer needs direct Launch Mainline download hrefs without opening the zip.");
  lines.push("- Use csv/launch-receipt-follow-ups.csv when handing the full follow-up queue to another operator.");
  return lines.join("\n");
}

function buildDeveloperOpsSnapshotPayload({
  generatedAt = nowIso(),
  developer = null,
  actor = null,
  accessibleProjects = [],
  projects = [],
  filters = {},
  accounts = {},
  entitlements = {},
  sessions = {},
  bindings = {},
  blocks = {},
  auditLogs = {}
} = {}) {
  const normalizedProjects = projects.map((item) => normalizeDeveloperOpsProjectItem(item));
  const normalizedAccounts = (accounts.items || []).map((item) => normalizeDeveloperOpsAccountItem(item));
  const normalizedEntitlements = (entitlements.items || []).map((item) => normalizeDeveloperOpsEntitlementItem(item));
  const normalizedSessions = (sessions.items || []).map((item) => normalizeDeveloperOpsSessionItem(item));
  const normalizedBindings = (bindings.items || []).map((item) => normalizeDeveloperOpsBindingItem(item));
  const normalizedBlocks = (blocks.items || []).map((item) => normalizeDeveloperOpsBlockItem(item));
  const normalizedAuditLogs = (auditLogs.items || []).map((item) => normalizeDeveloperOpsAuditLogItem(item));
  const scopeTag = sanitizeExportNameSegment(filters.productCode || "all-projects", "developer-ops");
  const timestampTag = buildExportTimestampTag(generatedAt);
  const scope = {
    accessibleProjectCount: accessibleProjects.length,
    exportedProjectCount: normalizedProjects.length,
    productCode: filters.productCode || null,
    channel: filters.channel || null,
    username: filters.username || null,
    search: filters.search || null,
    eventType: filters.eventType || null,
    actorType: filters.actorType || null,
    entityType: filters.entityType || null,
    auditLimit: Number(filters.limit ?? auditLogs.filters?.limit ?? 0)
  };
  const routeReview = buildDeveloperOpsRouteReviewPayload({
    filters,
    accounts: normalizedAccounts,
    entitlements: normalizedEntitlements,
    sessions: normalizedSessions,
    bindings: normalizedBindings,
    blocks: normalizedBlocks,
    auditLogs: normalizedAuditLogs
  });
  routeReview.downloads = buildDeveloperOpsRouteReviewDownloads(scope, routeReview);
  routeReview.mainlineHandoff = buildDeveloperOpsMainlineHandoff(scope);
  routeReview.continuations = buildDeveloperOpsRouteReviewContinuations(scope, routeReview);
  const primaryContinuationKey = routeReview.primaryMatch?.kind && routeReview.primaryMatch?.item
    ? buildDeveloperOpsRouteReviewContinuationKey(routeReview.primaryMatch.kind, routeReview.primaryMatch.item)
    : "";
  routeReview.continuation = buildDeveloperOpsRouteReviewContinuation(routeReview);
  if (primaryContinuationKey && routeReview.continuations?.[primaryContinuationKey]) {
    routeReview.continuation = routeReview.continuations[primaryContinuationKey];
  }
  routeReview.actions = buildDeveloperOpsRouteReviewActions(routeReview);
  const overview = buildSnapshotOverview({
    generatedAt,
    projects: normalizedProjects,
    accounts: normalizedAccounts,
    entitlements: normalizedEntitlements,
    sessions: normalizedSessions,
    bindings: normalizedBindings,
    blocks: normalizedBlocks,
    auditLogs: normalizedAuditLogs,
    scope
  });
  const launchReceiptFollowUps = Array.isArray(overview.launchReceiptFollowUps)
    ? overview.launchReceiptFollowUps
    : [];
  const launchReceiptFollowUpPriorities = buildLaunchReceiptFollowUpPrioritySummary(launchReceiptFollowUps);
  const launchReceiptNextFollowUpBase = buildLaunchReceiptNextFollowUp(launchReceiptFollowUps);
  const launchReceiptNextFollowUp = launchReceiptNextFollowUpBase
    ? {
        ...launchReceiptNextFollowUpBase,
        recommendedAction: buildDeveloperOpsLaunchReceiptNextFollowUpAction(launchReceiptNextFollowUpBase),
        recommendedDownload: buildDeveloperOpsLaunchReceiptFollowUpDownload(launchReceiptNextFollowUpBase, scope)
      }
    : null;
  const initialLaunchOpsReadiness = buildDeveloperOpsInitialLaunchOpsReadinessPayload({
    scope,
    overview,
    launchReceiptFollowUps,
    launchReceiptFollowUpPriorities,
    launchReceiptNextFollowUp,
    mainlineHandoff: routeReview.mainlineHandoff
  });
  const launchReceiptFollowUpsForExport = Array.isArray(initialLaunchOpsReadiness?.followUpQueue)
    && initialLaunchOpsReadiness.followUpQueue.length
    ? initialLaunchOpsReadiness.followUpQueue
    : launchReceiptFollowUps;
  const launchReceiptAuditBackfill = Number(auditLogs.filters?.launchReceiptBackfill || 0);
  const launchReceiptAuditBackfillStatus = buildLaunchReceiptAuditBackfillStatus(launchReceiptAuditBackfill);
  const firstWaveHandoffBackfill = Number(auditLogs.filters?.firstWaveHandoffBackfill || 0);
  const firstWaveReadinessBackfill = Number(auditLogs.filters?.firstWaveReadinessBackfill || 0);
  const firstWaveAuditBackfillStatus = buildFirstWaveAuditBackfillStatus({
    handoffCount: firstWaveHandoffBackfill,
    readinessCount: firstWaveReadinessBackfill
  });

  const payload = {
    generatedAt,
    fileName: `rocksolid-developer-ops-${scopeTag}-${timestampTag}.json`,
    summaryFileName: `rocksolid-developer-ops-${scopeTag}-${timestampTag}-summary.txt`,
    developer,
    actor,
    scope,
    summary: {
      projects: normalizedProjects.length,
      accounts: normalizedAccounts.length,
      entitlements: normalizedEntitlements.length,
      sessions: normalizedSessions.length,
      bindings: normalizedBindings.length,
      blocks: normalizedBlocks.length,
      auditLogs: normalizedAuditLogs.length,
      launchReceiptAuditBackfill,
      launchReceiptAuditBackfillStatus,
      firstWaveHandoffBackfill,
      firstWaveReadinessBackfill,
      firstWaveAuditBackfillStatus,
      launchReceiptFollowUps: launchReceiptFollowUps.length,
      launchReceiptFollowUpPriorities,
      launchReceiptNextFollowUp,
      initialLaunchOpsReadiness
    },
    overview,
    mainlineHandoff: routeReview.mainlineHandoff,
    routeReview,
    projects: normalizedProjects,
    accounts: {
      total: Number(accounts.total ?? normalizedAccounts.length),
      filters: accounts.filters || {},
      items: normalizedAccounts
    },
    entitlements: {
      total: Number(entitlements.total ?? normalizedEntitlements.length),
      filters: entitlements.filters || {},
      items: normalizedEntitlements
    },
    sessions: {
      total: Number(sessions.total ?? normalizedSessions.length),
      filters: sessions.filters || {},
      items: normalizedSessions
    },
    bindings: {
      total: Number(bindings.total ?? normalizedBindings.length),
      filters: bindings.filters || {},
      items: normalizedBindings
    },
    blocks: {
      total: Number(blocks.total ?? normalizedBlocks.length),
      filters: blocks.filters || {},
      items: normalizedBlocks
    },
    auditLogs: {
      total: Number(auditLogs.total ?? normalizedAuditLogs.length),
      filters: auditLogs.filters || {},
      items: normalizedAuditLogs
    },
    csv: {
      projects: buildDeveloperOpsProjectsCsv(normalizedProjects),
      accounts: buildDeveloperOpsAccountsCsv(normalizedAccounts),
      entitlements: buildDeveloperOpsEntitlementsCsv(normalizedEntitlements),
      sessions: buildDeveloperOpsSessionsCsv(normalizedSessions),
      bindings: buildDeveloperOpsBindingsCsv(normalizedBindings),
      blocks: buildDeveloperOpsBlocksCsv(normalizedBlocks),
      auditLogs: buildDeveloperOpsAuditLogsCsv(normalizedAuditLogs),
      launchReceiptFollowUps: buildDeveloperOpsLaunchReceiptFollowUpsCsv(launchReceiptFollowUpsForExport)
    },
    notes: [
      "This export is scoped to the current developer actor and their assigned projects.",
      "Use the zip archive when you need a support handoff bundle with JSON, summary, and CSV snapshots.",
      "Audit logs are filtered separately from accounts, entitlements, sessions, bindings, and blocks."
    ]
  };

  payload.summaryText = buildDeveloperOpsSummaryText(payload);
  return payload;
}

function buildDeveloperOpsRouteReviewExportFiles(payload = {}) {
  const routeReview = payload.routeReview && typeof payload.routeReview === "object" ? payload.routeReview : {};
  if (!routeReview.active) {
    return [];
  }
  const downloads = routeReview.downloads && typeof routeReview.downloads === "object" ? routeReview.downloads : {};
  const files = [];
  const seenPaths = new Set();
  const appendRouteReviewFile = (descriptor = null, body = "") => {
    if (!descriptor?.fileName) {
      return;
    }
    const path = `route-review/${descriptor.fileName}`;
    if (seenPaths.has(path)) {
      return;
    }
    seenPaths.add(path);
    files.push({ path, body });
  };

  appendRouteReviewFile(downloads.primary, buildDeveloperOpsRouteReviewMatchSummaryText(payload, "primary"));
  if (routeReview.nextMatch) {
    appendRouteReviewFile(downloads.next, buildDeveloperOpsRouteReviewMatchSummaryText(payload, "next"));
  }
  if (Array.isArray(routeReview.remainingMatches) && routeReview.remainingMatches.length) {
    appendRouteReviewFile(downloads.remaining, buildDeveloperOpsRouteReviewRemainingSummaryText(payload));
  }
  const sectionDownloads = downloads.sections && typeof downloads.sections === "object" ? downloads.sections : {};
  for (const [section, descriptor] of Object.entries(sectionDownloads)) {
    appendRouteReviewFile(descriptor, buildDeveloperOpsRouteReviewSectionSummaryText(payload, section));
  }
  return files;
}

