    async developerConfirmOpsStabilizationHandoff(token, body = {}) {
      const session = requireDeveloperSession(db, token);
      requireDeveloperPermission(
        session,
        "ops.write",
        "DEVELOPER_OPS_FORBIDDEN",
        "You can only confirm stabilization handoff reviews for your assigned projects."
      );
      requireField(body, "productCode");

      const productCode = readProductCodeInput(body);
      const product = await getStoreActiveProductByCode(productCode);
      ensureDeveloperCanAccessProduct(
        db,
        session,
        {
          id: product.id,
          owner_developer_id: product.ownerDeveloperId ?? product.ownerDeveloper?.id ?? null
        },
        "ops.write",
        "DEVELOPER_OPS_FORBIDDEN",
        "You can only confirm stabilization handoff reviews for your assigned projects."
      );

      const channel = normalizeChannel(body.channel, "stable");
      const rawDecision = String(body.decision ?? "confirmed").trim().toLowerCase();
      const decision = rawDecision.replace(/[^a-z0-9._-]/g, "_") || "confirmed";
      const confirmedAt = nowIso();
      const note = String(body.note ?? body.notes ?? "").trim().slice(0, 500);
      const handoffFileName = "developer-ops-stabilization-handoff.txt";
      const traceabilityParams = { productCode: product.code, channel };
      const opsStabilizationHandoffDownload = createLaunchWorkflowDownloadShortcut(
        "ops_stabilization_handoff",
        "developer-ops-stabilization-handoff.txt",
        "Developer Ops stabilization handoff",
        {
          source: "developer-ops",
          format: "stabilization-handoff",
          params: traceabilityParams
        }
      );
      const launchMainlineStabilizationHandoffDownload = createLaunchMainlineDownloadShortcut(
        "Launch Mainline stabilization handoff",
        "launch-mainline-stabilization-handoff.txt",
        "stabilization-handoff",
        traceabilityParams
      );
      const latestLaunchReceipt = buildSnapshotLatestLaunchReceipts(
        queryAuditLogRows(db, {
          productCodes: [product.code],
          limit: 100
        }).items,
        5,
        channel
      )[0] || null;
      const launchOpsOverviewContext = buildScopedLaunchOpsOverviewContext(
        traceabilityParams,
        body.launchOpsOverviewContext
        || latestLaunchReceipt?.launchOpsOverviewContext
      );
      const launchOpsOverviewDownload = buildLaunchOpsOverviewContextDownload(launchOpsOverviewContext);
      const traceability = {
        eventType: "developer.ops.stabilization-handoff.confirm",
        entityType: "developer_ops_stabilization_handoff",
        opsFiles: {
          handoffIndex: "handoff-index.txt",
          initialLaunchOpsReadiness: "initial-launch-ops-readiness.txt",
          launchReceiptNextFollowUp: "launch-receipt-next-follow-up.txt",
          stabilizationHandoff: "stabilization-handoff.txt",
          launchReceiptFollowUpsCsv: "csv/launch-receipt-follow-ups.csv",
          auditLogsCsv: "csv/audit-logs.csv"
        },
        launchMainlineFiles: {
          postLaunchHandoffIndex: "post-launch-handoff-index",
          stabilizationHandoff: "ops/stabilization-handoff.txt",
          summary: "summary",
          checksums: "checksums",
          zip: "zip"
        },
        opsDownloads: {
          stabilizationHandoff: opsStabilizationHandoffDownload
        },
        launchMainlineDownloads: {
          stabilizationHandoff: launchMainlineStabilizationHandoffDownload
        },
        launchOpsOverviewContext,
        launchOpsOverviewDownload
      };
      const confirmedBy = {
        actorType: session.actor_scope === "member" ? "developer_member" : "developer",
        actorScope: session.actor_scope,
        actorId: session.actor_id,
        username: session.username,
        role: session.member_role ?? "owner"
      };
      const auditLogId = auditDeveloperSession(
        db,
        session,
        traceability.eventType,
        traceability.entityType,
        product.id,
        {
          productCode: product.code,
          channel,
          decision,
          status: "confirmed",
          confirmedAt,
          handoffFileName,
          note,
          opsFiles: traceability.opsFiles,
          launchMainlineFiles: traceability.launchMainlineFiles,
          opsDownloads: traceability.opsDownloads,
          launchMainlineDownloads: traceability.launchMainlineDownloads,
          launchOpsOverviewContext: traceability.launchOpsOverviewContext,
          launchOpsOverviewDownload: traceability.launchOpsOverviewDownload
        }
      );

      return {
        version: "developer-ops-stabilization-handoff-confirmation/v1",
        status: "confirmed",
        productCode: product.code,
        productId: product.id,
        channel,
        decision,
        note,
        confirmedAt,
        confirmedBy,
        handoffFileName,
        handoffFormat: "stabilization-handoff",
        traceability,
        auditLogId,
        message: `Stabilization handoff confirmed for ${product.code} (${channel}).`
      };
    },

    async developerFirstWaveRecommendations(token, filters = {}) {
      const session = requireDeveloperSession(db, token);
      requireDeveloperPermission(
        session,
        "ops.read",
        "DEVELOPER_OPS_FORBIDDEN",
        "You can only view first-wave operations recommendations for your assigned projects."
      );

      const productCode = readProductCodeInput(filters);
      const channel = normalizeChannel(filters.channel, "stable");
      const limit = Math.min(Math.max(Number(filters.limit ?? 60), 1), 200);
      const product = await requireDeveloperOwnedProductByCode(
        db,
        store,
        session,
        productCode,
        "ops.read"
      );

      const [policiesPayload, cardsPayload, opsSnapshot] = await Promise.all([
        this.developerListPolicies(token, { productCode }),
        this.developerListCards(token, { productCode }),
        this.developerExportOpsSnapshot(token, {
          productCode,
          channel,
          limit
        })
      ]);
      const policyItems = Array.isArray(policiesPayload) ? policiesPayload : [];
      const activePolicies = policyItems.filter((item) => normalizeProductStatus(item?.status || "active") === "active");
      const cardItems = Array.isArray(cardsPayload?.items) ? cardsPayload.items : [];
      const inventoryStates = buildLaunchRecommendedCardInventoryStates(product, activePolicies, cardItems);
      const payload = buildDeveloperOpsFirstWaveRecommendationsPayload({
        product,
        channel,
        inventoryStates,
        cards: cardItems,
        opsSnapshot
      });
      const auditLogId = auditDeveloperSession(
        db,
        session,
        "developer.ops.first-wave.recommendations",
        "developer_ops_first_wave_recommendations",
        product.id,
        {
          productCode,
          channel,
          inventoryStatus: payload.inventory.status,
          firstCardStatus: payload.firstCards.status,
          firstRoundOpsStatus: payload.firstRoundOps.status,
          missingCount: payload.inventory.missingCount,
          lowCount: payload.inventory.lowCount,
          readyCount: payload.inventory.readyCount,
          freshCardCount: payload.inventory.freshCardCount,
          recommendedCardCount: payload.firstCards.recommendedCardCount,
          issuedFreshCardCount: payload.firstCards.issuedFreshCardCount,
          latestLaunchReceiptOperation: payload.traceability.latestLaunchReceipt?.operation || null,
          opsSnapshotFileName: payload.traceability.opsSnapshotFileName || null,
          launchReadinessBridgeStatus: payload.launchReadinessBridge?.status || null,
          launchReadinessBridgeCurrentGate: payload.launchReadinessBridge?.currentGate || null,
          launchReadinessBridgeNextActionKey: payload.launchReadinessBridge?.nextAction?.key || null,
          launchReadinessBridgeReadySegmentCount: payload.launchReadinessBridge?.readySegmentCount ?? null,
          launchReadinessBridgeSegmentCount: payload.launchReadinessBridge?.segmentCount ?? null
        }
      );

      return {
        ...payload,
        auditLogId
      };
    },

